package app

import (
	"time"

	"github.com/charmbracelet/bubbles/key"
	tea "github.com/charmbracelet/bubbletea"
	"github.com/charmbracelet/lipgloss"
)

// ViewState represents the current active view
type ViewState int

const (
	ViewDashboard ViewState = iota
	ViewLogs
	ViewHelp
)

// Model represents the root application state
type Model struct {
	// Current view state
	currentView ViewState

	// UI dimensions
	width  int
	height int

	// Application state
	ready    bool
	quitting bool
	err      error

	// Last update time for performance tracking
	lastUpdate time.Time

	// Key bindings
	keys KeyMap
}

// KeyMap defines the key bindings for the application
type KeyMap struct {
	Tab   key.Binding
	Quit  key.Binding
	Help  key.Binding
	Enter key.Binding
}

// DefaultKeyMap returns the default key bindings
func DefaultKeyMap() KeyMap {
	return KeyMap{
		Tab: key.NewBinding(
			key.WithKeys("tab"),
			key.WithHelp("tab", "switch view"),
		),
		Quit: key.NewBinding(
			key.WithKeys("q", "esc", "ctrl+c"),
			key.WithHelp("q", "quit"),
		),
		Help: key.NewBinding(
			key.WithKeys("?"),
			key.WithHelp("?", "help"),
		),
		Enter: key.NewBinding(
			key.WithKeys("enter"),
			key.WithHelp("enter", "execute"),
		),
	}
}

// NewModel creates a new application model
func NewModel() Model {
	return Model{
		currentView: ViewDashboard,
		ready:       false,
		quitting:    false,
		lastUpdate:  time.Now(),
		keys:        DefaultKeyMap(),
	}
}

// Init initializes the application
func (m Model) Init() tea.Cmd {
	return nil
}

// View renders the application
func (m Model) View() string {
	if m.err != nil {
		return lipgloss.NewStyle().
			Foreground(lipgloss.Color("9")).
			Render("Error: " + m.err.Error())
	}

	if !m.ready {
		return "Loading MCF TUI..."
	}

	switch m.currentView {
	case ViewDashboard:
		return m.dashboardView()
	case ViewLogs:
		return m.logsView()
	case ViewHelp:
		return m.helpView()
	default:
		return "Unknown view"
	}
}

// dashboardView renders the main dashboard
func (m Model) dashboardView() string {
	return lipgloss.NewStyle().
		Padding(1).
		Render("🚀 MCF TUI Dashboard\n\nPress tab to switch views, q to quit")
}

// logsView renders the logs view
func (m Model) logsView() string {
	return lipgloss.NewStyle().
		Padding(1).
		Render("📋 Logs View\n\nPress tab to switch views, q to quit")
}

// helpView renders the help view
func (m Model) helpView() string {
	return lipgloss.NewStyle().
		Padding(1).
		Render("❓ Help View\n\nPress tab to switch views, q to quit")
}

package app

import (
	tea "github.com/charmbracelet/bubbletea"
)

// Update handles all application state updates
func (m Model) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {

	case tea.WindowSizeMsg:
		m.width = msg.Width
		m.height = msg.Height
		if !m.ready {
			m.ready = true
		}
		return m, nil

	case tea.KeyMsg:
		return m.handleKeyPress(msg)

	case errMsg:
		m.err = msg
		return m, nil

	default:
		return m, nil
	}
}

// errMsg wraps errors for the tea.Msg interface
type errMsg error

// handleKeyPress processes keyboard input
func (m Model) handleKeyPress(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	// Global key bindings
	switch {
	case key.Matches(msg, m.keys.Quit):
		m.quitting = true
		return m, tea.Quit

	case key.Matches(msg, m.keys.Tab):
		m.currentView = m.nextView()
		return m, nil

	case key.Matches(msg, m.keys.Help):
		m.currentView = ViewHelp
		return m, nil
	}

	// View-specific key handling
	switch m.currentView {
	case ViewDashboard:
		return m.handleDashboardKeys(msg)
	case ViewLogs:
		return m.handleLogsKeys(msg)
	case ViewHelp:
		return m.handleHelpKeys(msg)
	}

	return m, nil
}

// nextView returns the next view in the cycle
func (m Model) nextView() ViewState {
	switch m.currentView {
	case ViewDashboard:
		return ViewLogs
	case ViewLogs:
		return ViewHelp
	case ViewHelp:
		return ViewDashboard
	default:
		return ViewDashboard
	}
}

// handleDashboardKeys handles key presses in dashboard view
func (m Model) handleDashboardKeys(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	// Dashboard-specific key handling will be added here
	return m, nil
}

// handleLogsKeys handles key presses in logs view
func (m Model) handleLogsKeys(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	// Logs-specific key handling will be added here
	return m, nil
}

// handleHelpKeys handles key presses in help view
func (m Model) handleHelpKeys(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	// Help-specific key handling will be added here
	return m, nil
}

