package ui

import (
	"fmt"
	"strings"

	"github.com/charmbracelet/lipgloss"
)

// Dashboard represents the main dashboard component
type Dashboard struct {
	width  int
	height int
}

// NewDashboard creates a new dashboard component
func NewDashboard() *Dashboard {
	return &Dashboard{}
}

// SetSize updates the dashboard dimensions
func (d *Dashboard) SetSize(width, height int) {
	d.width = width
	d.height = height
}

// Render renders the dashboard view
func (d *Dashboard) Render() string {
	if d.width <= 0 || d.height <= 0 {
		return "Initializing..."
	}

	// Header section
	header := Styles.Header.Render("🚀 MCF TUI Dashboard")

	// Status section
	status := d.renderStatus()

	// Quick actions section
	actions := d.renderQuickActions()

	// Logs section
	logs := d.renderLogViewer()

	// Combine all sections
	content := lipgloss.JoinVertical(
		lipgloss.Left,
		header,
		"",
		status,
		"",
		actions,
		"",
		logs,
	)

	return ViewBox(content, d.width, d.height)
}

// renderStatus renders the status section
func (d *Dashboard) renderStatus() string {
	statusItems := []string{
		"📦 MCF Version: v1.0.0",
		"🧠 Serena: Connected",
		"⚡ Status: Ready",
		"🕐 Uptime: 0m 15s",
	}

	statusContent := strings.Join(statusItems, "\n")

	return Styles.Body.
		Border(lipgloss.RoundedBorder()).
		BorderForeground(Colors.Success).
		Width(d.width - 6).
		Render(lipgloss.JoinVertical(
			lipgloss.Left,
			Styles.Subtitle.Render("System Status"),
			"",
			statusContent,
		))
}

// renderQuickActions renders the quick actions section
func (d *Dashboard) renderQuickActions() string {
	buttons := []string{
		Styles.Button.Render("📊 Status"),
		Styles.Button.Render("📋 Logs"), 
		Styles.Button.Render("⚙️  Config"),
		Styles.Button.Render("❓ Help"),
	}

	buttonsRow := lipgloss.JoinHorizontal(
		lipgloss.Center,
		buttons[0], "  ",
		buttons[1], "  ", 
		buttons[2], "  ",
		buttons[3],
	)

	return Styles.Body.
		Border(lipgloss.RoundedBorder()).
		BorderForeground(Colors.Accent).
		Width(d.width - 6).
		Render(lipgloss.JoinVertical(
			lipgloss.Left,
			Styles.Subtitle.Render("Quick Actions"),
			"",
			buttonsRow,
		))
}

// renderLogViewer renders the log viewer section
func (d *Dashboard) renderLogViewer() string {
	// Sample log entries
	logEntries := []string{
		"[INFO] MCF TUI started successfully",
		"[INFO] Serena connection established", 
		"[INFO] Configuration loaded from ~/.mcf/config.yaml",
		"[DEBUG] Dashboard view initialized",
		"[INFO] Ready for user input",
	}

	logContent := strings.Join(logEntries, "\n")

	return Styles.Body.
		Border(lipgloss.RoundedBorder()).
		BorderForeground(Colors.Secondary).
		Width(d.width - 6).
		Height(8).
		Render(lipgloss.JoinVertical(
			lipgloss.Left,
			Styles.Subtitle.Render("Recent Logs (last 5 entries)"),
			"",
			logContent,
		))
}

package ui

import (
	"fmt"
	"strings"
)

// Navigation represents the tab navigation component
type Navigation struct {
	tabs        []Tab
	activeTab   int
	width       int
}

// Tab represents a navigation tab
type Tab struct {
	Label string
	Key   string
	Icon  string
}

// NewNavigation creates a new navigation component
func NewNavigation() *Navigation {
	tabs := []Tab{
		{Label: "Dashboard", Key: "dashboard", Icon: "🚀"},
		{Label: "Logs", Key: "logs", Icon: "📋"},
		{Label: "Help", Key: "help", Icon: "❓"},
	}

	return &Navigation{
		tabs:      tabs,
		activeTab: 0,
	}
}

// SetWidth updates the navigation width
func (n *Navigation) SetWidth(width int) {
	n.width = width
}

// SetActiveTab sets the active tab by index
func (n *Navigation) SetActiveTab(index int) {
	if index >= 0 && index < len(n.tabs) {
		n.activeTab = index
	}
}

// GetActiveTab returns the current active tab index
func (n *Navigation) GetActiveTab() int {
	return n.activeTab
}

// NextTab moves to the next tab
func (n *Navigation) NextTab() {
	n.activeTab = (n.activeTab + 1) % len(n.tabs)
}

// PrevTab moves to the previous tab
func (n *Navigation) PrevTab() {
	n.activeTab = (n.activeTab - 1 + len(n.tabs)) % len(n.tabs)
}

// Render renders the navigation bar
func (n *Navigation) Render() string {
	var renderedTabs []string

	for i, tab := range n.tabs {
		tabContent := fmt.Sprintf("%s %s", tab.Icon, tab.Label)

		if i == n.activeTab {
			// Active tab styling
			renderedTab := Styles.ActiveButton.Render(tabContent)
			renderedTabs = append(renderedTabs, renderedTab)
		} else {
			// Inactive tab styling
			renderedTab := Styles.Button.Render(tabContent)
			renderedTabs = append(renderedTabs, renderedTab)
		}
	}

	// Join tabs with spacing
	tabBar := strings.Join(renderedTabs, "  ")

	// Center the tab bar
	return StatusLine(tabBar, n.width)
}

// GetCurrentTabKey returns the key of the currently active tab
func (n *Navigation) GetCurrentTabKey() string {
	if n.activeTab >= 0 && n.activeTab < len(n.tabs) {
		return n.tabs[n.activeTab].Key
	}
	return ""
}

package config

import (
	"os"
	"path/filepath"
)

// Config represents the application configuration
type Config struct {
	// Application settings
	LogLevel    string `yaml:"log_level"`
	Theme       string `yaml:"theme"`
	RefreshRate int    `yaml:"refresh_rate"`

	// MCF integration settings
	MCF MCFConfig `yaml:"mcf"`

	// UI settings
	UI UIConfig `yaml:"ui"`
}

// MCFConfig represents MCF-specific configuration
type MCFConfig struct {
	ConfigPath  string `yaml:"config_path"`
	LogPath     string `yaml:"log_path"`
	SerenaURL   string `yaml:"serena_url"`
	MaxLogLines int    `yaml:"max_log_lines"`
}

// UIConfig represents UI-specific configuration
type UIConfig struct {
	ShowStatusBar    bool `yaml:"show_status_bar"`
	ShowLineNumbers  bool `yaml:"show_line_numbers"`
	CompactMode      bool `yaml:"compact_mode"`
	AnimationEnabled bool `yaml:"animation_enabled"`
}

// DefaultConfig returns the default configuration
func DefaultConfig() *Config {
	homeDir, _ := os.UserHomeDir()

	return &Config{
		LogLevel:    "info",
		Theme:       "default",
		RefreshRate: 1000, // milliseconds

		MCF: MCFConfig{
			ConfigPath:  filepath.Join(homeDir, ".mcf", "config.yaml"),
			LogPath:     filepath.Join(homeDir, ".mcf", "logs"),
			SerenaURL:   "http://localhost:24282",
			MaxLogLines: 100,
		},

		UI: UIConfig{
			ShowStatusBar:    true,
			ShowLineNumbers:  false,
			CompactMode:      false,
			AnimationEnabled: true,
		},
	}
}

// Load loads configuration from file (placeholder for future implementation)
func Load() (*Config, error) {
	// For now, return default config
	// TODO: Implement YAML config file loading
	return DefaultConfig(), nil
}

// GetConfigPath returns the path to the configuration file
func GetConfigPath() (string, error) {
	homeDir, err := os.UserHomeDir()
	if err != nil {
		return "", err
	}

	configDir := filepath.Join(homeDir, ".mcf")

	// Ensure config directory exists
	err = os.MkdirAll(configDir, 0755)
	if err != nil {
		return "", err
	}

	return filepath.Join(configDir, "tui-config.yaml"), nil
}

