	}

	// Create and run the program
	p := tea.NewProgram(model, opts...)

	if _, err := p.Run(); err != nil {
		fmt.Printf("Application error: %v\n", err)
		os.Exit(1)
	}

	// Suppress unused variable warning for now
	_ = cfg
}

