	case key.Matches(msg, m.keys.Tab):
		m.navigation.NextTab()
		m.currentView = ViewState(m.navigation.GetActiveTab())
		return m, nil

	case key.Matches(msg, m.keys.Help):
		m.navigation.SetActiveTab(2) // Help is index 2
		m.currentView = ViewHelp
		return m, nil
	}

	// View-specific key handling
	switch m.currentView {
	case ViewDashboard:
		return m.handleDashboardKeys(msg)
	case ViewLogs:
		return m.handleLogsKeys(msg)
	case ViewHelp:
		return m.handleHelpKeys(msg)
	}

	return m, nil
}

// nextView returns the next view in the cycle
func (m Model) nextView() ViewState {
	switch m.currentView {
	case ViewDashboard:
		return ViewLogs
	case ViewLogs:
		return ViewHelp
	case ViewHelp:
		return ViewDashboard
	default:
		return ViewDashboard
	}
}

// handleDashboardKeys handles key presses in dashboard view
func (m Model) handleDashboardKeys(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	// Dashboard-specific key handling will be added here
	return m, nil
}

// handleLogsKeys handles key presses in logs view
func (m Model) handleLogsKeys(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	switch msg.String() {
	case "up", "k":
		m.logsViewer.ScrollUp()
		return m, nil
	case "down", "j":
		m.logsViewer.ScrollDown()
		return m, nil
	}
	return m, nil
}

// handleHelpKeys handles key presses in help view
func (m Model) handleHelpKeys(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	// Help-specific key handling will be added here
	return m, nil
}

// handleCommandBarInput handles input when command bar is active
func (m Model) handleCommandBarInput(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	switch {
	case key.Matches(msg, m.keys.Enter):
		command, err := m.commandBar.ExecuteCommand()
		if err != nil {
			m.logsViewer.AddLog("[ERROR] " + err.Error())
			return m, nil
		}
		return m.processCommand(command)

	case key.Matches(msg, m.keys.Quit):
		m.commandBar.Deactivate()
		return m, nil

	default:
		// Forward input to command bar
		m.commandBar.Update(msg)
		return m, nil
	}
}

// processCommand processes an executed command
func (m Model) processCommand(command string) (tea.Model, tea.Cmd) {
	// Add command to logs
	m.logsViewer.AddLog("[CMD] Executed: " + command)

	// Process specific commands
	switch command {
	case ":status":
		// Retrieve MCF status from client
		status, err := m.mcfClient.GetStatus()
		if err != nil {
			m.logsViewer.AddLog("[ERROR] Failed to retrieve MCF status: " + err.Error())
		} else {
			m.logsViewer.AddLog("[INFO] MCF Status: " + status)
		}

	case ":logs":
		m.navigation.SetActiveTab(1) // Logs is index 1
		m.currentView = ViewLogs

	case ":help":
		m.navigation.SetActiveTab(2) // Help is index 2
		m.currentView = ViewHelp

	case ":quit":
		m.quitting = true
		return m, tea.Quit

	case ":config":
		// Load configuration
		config, err := m.mcfClient.LoadConfig()
		if err != nil {
			m.logsViewer.AddLog("[ERROR] Failed to load config: " + err.Error())
		} else {
			m.logsViewer.AddLog("[INFO] Config loaded: " + config)
		}

	case ":refresh":
		// Trigger data refresh
		err := m.mcfClient.Refresh()
		if err != nil {
			m.logsViewer.AddLog("[ERROR] Refresh failed: " + err.Error())
		} else {
			m.logsViewer.AddLog("[INFO] Data refreshed successfully")
		}

	case ":export":
		// Export current dashboard data
		exportPath, err := m.dashboard.ExportData()
		if err != nil {
			m.logsViewer.AddLog("[ERROR] Export failed: " + err.Error())
		} else {
			m.logsViewer.AddLog("[INFO] Data exported to: " + exportPath)
		}

	default:
		// Advanced command parsing with argument support
		parts := strings.Split(command, " ")
		switch parts[0] {
		case ":search":
			if len(parts) > 1 {
				searchResults, err := m.mcfClient.Search(parts[1])
				if err != nil {
					m.logsViewer.AddLog("[ERROR] Search failed: " + err.Error())
				} else {
					m.logsViewer.AddLog("[INFO] Search results: " + strings.Join(searchResults, ", "))
				}
			} else {
				m.logsViewer.AddLog("[ERROR] :search requires a search term")
			}

		default:
			m.logsViewer.AddLog("[ERROR] Unknown command: " + command)
		}
	}

	return m, nil
}

