package mcf

import (
	"context"
	"encoding/json"
	"fmt"
	"io"
	"log/slog"
	"net/http"
	"sync"
	"time"
)

// ClientConfig allows configuration of MCF client
type ClientConfig struct {
	BaseURL         string
	Timeout         time.Duration
	RetryAttempts   int
	RetryDelay      time.Duration
	Logger          *slog.Logger
}

// Client represents an MCF integration client with advanced features
type Client struct {
	baseURL      string
	httpClient   *http.Client
	config       ClientConfig
	mu           sync.RWMutex
	lastStatus   *Status
	lastChecksum string
}

// Status represents MCF system status with extended details
type Status struct {
	Version          string    `json:"version"`
	Uptime           string    `json:"uptime"`
	SerenaURL        string    `json:"serena_url"`
	Connected        bool      `json:"connected"`
	LastUpdate       time.Time `json:"last_update"`
	ConfigVersion    string    `json:"config_version,omitempty"`
	SystemLoad       float64   `json:"system_load,omitempty"`
	AvailableMemory  uint64    `json:"available_memory,omitempty"`
}

// NewClient creates a new MCF client with advanced configuration options
func NewClient(cfg ClientConfig) *Client {
	if cfg.Timeout == 0 {
		cfg.Timeout = 10 * time.Second
	}
	if cfg.RetryAttempts == 0 {
		cfg.RetryAttempts = 3
	}
	if cfg.RetryDelay == 0 {
		cfg.RetryDelay = 1 * time.Second
	}
	if cfg.Logger == nil {
		cfg.Logger = slog.Default()
	}

	return &Client{
		baseURL: cfg.BaseURL,
		httpClient: &http.Client{
			Timeout: cfg.Timeout,
			Transport: &http.Transport{
				MaxIdleConns:        10,
				MaxIdleConnsPerHost: 2,
				IdleConnTimeout:     30 * time.Second,
			},
		},
		config: cfg,
	}
}

// GetStatus retrieves the current MCF system status with retries and logging
func (c *Client) GetStatus(ctx context.Context) (*Status, error) {
	var status *Status
	var err error

	for attempt := 0; attempt < c.config.RetryAttempts; attempt++ {
		status, err = c.fetchStatus(ctx)
		if err == nil {
			c.mu.Lock()
			c.lastStatus = status
			c.mu.Unlock()
			return status, nil
		}

		c.config.Logger.Error("Failed to retrieve MCF status", 
			slog.Int("attempt", attempt+1), 
			slog.String("error", err.Error()),
		)

		select {
		case <-ctx.Done():
			return nil, ctx.Err()
		case <-time.After(c.config.RetryDelay):
			continue
		}
	}

	return nil, fmt.Errorf("failed to retrieve MCF status after %d attempts: %w", 
		c.config.RetryAttempts, err)
}

// fetchStatus performs the actual HTTP request to get system status
func (c *Client) fetchStatus(ctx context.Context) (*Status, error) {
	req, err := http.NewRequestWithContext(ctx, "GET", c.baseURL+"/status", nil)
	if err != nil {
		return nil, fmt.Errorf("failed to create status request: %w", err)
	}

	resp, err := c.httpClient.Do(req)
	if err != nil {
		return nil, fmt.Errorf("status request failed: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("unexpected status code: %d", resp.StatusCode)
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("failed to read response body: %w", err)
	}

	var status Status
	if err := json.Unmarshal(body, &status); err != nil {
		return nil, fmt.Errorf("failed to parse status response: %w", err)
	}

	return &status, nil
}

// GetLogs retrieves MCF logs with context and retry support
func (c *Client) GetLogs(ctx context.Context, maxLines int) ([]string, error) {
	req, err := http.NewRequestWithContext(ctx, "GET", c.baseURL+"/logs", nil)
	if err != nil {
		return nil, fmt.Errorf("failed to create logs request: %w", err)
	}

	q := req.URL.Query()
	q.Add("max_lines", fmt.Sprintf("%d", maxLines))
	req.URL.RawQuery = q.Encode()

	resp, err := c.httpClient.Do(req)
	if err != nil {
		return nil, fmt.Errorf("logs request failed: %w", err)
	}
	defer resp.Body.Close()

	var logs []string
	if err := json.NewDecoder(resp.Body).Decode(&logs); err != nil {
		return nil, fmt.Errorf("failed to parse logs: %w", err)
	}

	return logs, nil
}

// ExecuteCommand sends a command to MCF with enhanced error handling
func (c *Client) ExecuteCommand(ctx context.Context, command string) (string, error) {
	payload := struct {
		Command string `json:"command"`
	}{Command: command}

	jsonPayload, err := json.Marshal(payload)
	if err != nil {
		return "", fmt.Errorf("failed to marshal command payload: %w", err)
	}

	req, err := http.NewRequestWithContext(ctx, "POST", c.baseURL+"/execute", 
		io.NopCloser(bytes.NewBuffer(jsonPayload)))
	if err != nil {
		return "", fmt.Errorf("failed to create execute request: %w", err)
	}
	req.Header.Set("Content-Type", "application/json")

	resp, err := c.httpClient.Do(req)
	if err != nil {
		return "", fmt.Errorf("command execution failed: %w", err)
	}
	defer resp.Body.Close()

	var result struct {
		Output string `json:"output"`
		Error  string `json:"error,omitempty"`
	}

	if err := json.NewDecoder(resp.Body).Decode(&result); err != nil {
		return "", fmt.Errorf("failed to parse command result: %w", err)
	}

	if result.Error != "" {
		return "", fmt.Errorf("command execution error: %s", result.Error)
	}

	return result.Output, nil
}

// CheckConnection verifies MCF service connectivity
func (c *Client) CheckConnection(ctx context.Context) error {
	_, err := c.GetStatus(ctx)
	return err
}

// IsSerenaConnected checks Serena component accessibility
func (c *Client) IsSerenaConnected(ctx context.Context) bool {
	status, err := c.GetStatus(ctx)
	return err == nil && status.Connected
}

// Clone creates a thread-safe copy of the client
func (c *Client) Clone() *Client {
	c.mu.RLock()
	defer c.mu.RUnlock()

	return &Client{
		baseURL:      c.baseURL,
		httpClient:   c.httpClient,
		config:       c.config,
		lastStatus:   c.lastStatus,
		lastChecksum: c.lastChecksum,
	}
}

