package ui

import (
	"fmt"
	"strings"

	"github.com/charmbracelet/lipgloss"
)

// LogsViewer represents the logs viewer component
type LogsViewer struct {
	width  int
	height int
	logs   []string
	scroll int
}

// NewLogsViewer creates a new logs viewer component
func NewLogsViewer() *LogsViewer {
	return &LogsViewer{
		logs: []string{
			"[2025-08-31 14:30:15] [INFO] MCF TUI started successfully",
			"[2025-08-31 14:30:15] [INFO] Serena connection established", 
			"[2025-08-31 14:30:15] [INFO] Configuration loaded from ~/.mcf/config.yaml",
			"[2025-08-31 14:30:16] [DEBUG] Dashboard view initialized",
			"[2025-08-31 14:30:16] [INFO] Ready for user input",
			"[2025-08-31 14:30:20] [DEBUG] User switched to logs view",
			"[2025-08-31 14:30:25] [INFO] MCF client connection verified",
			"[2025-08-31 14:30:30] [DEBUG] UI refresh cycle completed",
		},
		scroll: 0,
	}
}

// SetSize updates the logs viewer dimensions
func (l *LogsViewer) SetSize(width, height int) {
	l.width = width
	l.height = height
}

// AddLog adds a new log entry
func (l *LogsViewer) AddLog(logEntry string) {
	l.logs = append(l.logs, logEntry)

	// Auto-scroll to bottom for new entries
	maxVisible := l.height - 6 // Account for borders and headers
	if len(l.logs) > maxVisible {
		l.scroll = len(l.logs) - maxVisible
	}
}

// ScrollUp scrolls the log view up
func (l *LogsViewer) ScrollUp() {
	if l.scroll > 0 {
		l.scroll--
	}
}

// ScrollDown scrolls the log view down
func (l *LogsViewer) ScrollDown() {
	maxScroll := len(l.logs) - (l.height - 6)
	if maxScroll < 0 {
		maxScroll = 0
	}
	if l.scroll < maxScroll {
		l.scroll++
	}
}

// Render renders the logs viewer
func (l *LogsViewer) Render() string {
	if l.width <= 0 || l.height <= 0 {
		return "Initializing logs viewer..."
	}

	// Header
	header := Styles.Header.Render("📋 MCF Logs Viewer")

	// Calculate visible logs
	maxVisible := l.height - 6 // Account for borders and headers
	visibleLogs := l.getVisibleLogs(maxVisible)

	// Format log entries
	var logLines []string
	for i, log := range visibleLogs {
		if i == len(visibleLogs)-1 {
			// Highlight the most recent log
			logLines = append(logLines, 
				lipgloss.NewStyle().
					Foreground(Colors.Success).
					Render(log))
		} else {
			logLines = append(logLines, log)
		}
	}

	// Join log lines
	logsContent := strings.Join(logLines, "\n")

	// Create scrollable log area
	logArea := Styles.Body.
		Border(lipgloss.RoundedBorder()).
		BorderForeground(Colors.Secondary).
		Width(l.width - 6).
		Height(maxVisible).
		Render(logsContent)

	// Status bar
	totalLogs := len(l.logs)
	statusText := lipgloss.NewStyle().
		Foreground(Colors.Muted).
		Render(fmt.Sprintf("📊 Total logs: %s | Use ↑/↓ to scroll, tab to switch views",
			lipgloss.NewStyle().Foreground(Colors.Accent).Render(fmt.Sprintf("%d", totalLogs))))

	// Combine all sections
	content := lipgloss.JoinVertical(
		lipgloss.Left,
		header,
		"",
		logArea,
		"",
		statusText,
	)

	return ViewBox(content, l.width, l.height)
}

// getVisibleLogs returns the logs that should be visible based on scroll position
func (l *LogsViewer) getVisibleLogs(maxVisible int) []string {
	if len(l.logs) == 0 {
		return []string{"No logs available"}
	}

	start := l.scroll
	end := start + maxVisible

	if end > len(l.logs) {
		end = len(l.logs)
	}

	if start >= len(l.logs) {
		start = len(l.logs) - 1
		if start < 0 {
			start = 0
		}
	}

	return l.logs[start:end]
}

package app

import (
	"strings"

	"github.com/charmbracelet/bubbles/key"
	tea "github.com/charmbracelet/bubbletea"
)

// Update handles all application state updates
func (m Model) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {

	case tea.WindowSizeMsg:
		m.width = msg.Width
		m.height = msg.Height
		if !m.ready {
			m.ready = true
		}
		return m, nil

	case tea.KeyMsg:
		return m.handleKeyPress(msg)

	case errMsg:
		m.err = msg
		return m, nil

	default:
		// Update command bar with any message
		m.commandBar.Update(msg)
		return m, nil
	}
}

// errMsg wraps errors for the tea.Msg interface
type errMsg error

// handleKeyPress processes keyboard input
func (m Model) handleKeyPress(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	// If command bar is active, handle its input first
	if m.commandBar.IsActive() {
		return m.handleCommandBarInput(msg)
	}

	// Global key bindings
	switch {
	case key.Matches(msg, m.keys.Quit):
		m.quitting = true
		return m, tea.Quit

	case key.Matches(msg, m.keys.Command):
		m.commandBar.Activate()
		return m, nil

	case key.Matches(msg, m.keys.Tab):
		m.navigation.NextTab()
		m.currentView = ViewState(m.navigation.GetActiveTab())
		return m, nil

	case key.Matches(msg, m.keys.Help):
		m.navigation.SetActiveTab(2) // Help is index 2
		m.currentView = ViewHelp
		return m, nil
	}

	// View-specific key handling
	switch m.currentView {
	case ViewDashboard:
		return m.handleDashboardKeys(msg)
	case ViewLogs:
		return m.handleLogsKeys(msg)
	case ViewHelp:
		return m.handleHelpKeys(msg)
	}

	return m, nil
}

// nextView returns the next view in the cycle
func (m Model) nextView() ViewState {
	switch m.currentView {
	case ViewDashboard:
		return ViewLogs
	case ViewLogs:
		return ViewHelp
	case ViewHelp:
		return ViewDashboard
	default:
		return ViewDashboard
	}
}

// handleDashboardKeys handles key presses in dashboard view
func (m Model) handleDashboardKeys(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	// Dashboard-specific key handling will be added here
	return m, nil
}

// handleLogsKeys handles key presses in logs view
func (m Model) handleLogsKeys(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	switch msg.String() {
	case "up", "k":
		m.logsViewer.ScrollUp()
		return m, nil
	case "down", "j":
		m.logsViewer.ScrollDown()
		return m, nil
	}
	return m, nil
}

// handleHelpKeys handles key presses in help view
func (m Model) handleHelpKeys(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	// Help-specific key handling will be added here
	return m, nil
}

// handleCommandBarInput handles input when command bar is active
func (m Model) handleCommandBarInput(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	switch {
	case key.Matches(msg, m.keys.Enter):
		command, err := m.commandBar.ExecuteCommand()
		if err != nil {
			m.logsViewer.AddLog("[ERROR] " + err.Error())
			return m, nil
		}
		return m.processCommand(command)

	case key.Matches(msg, m.keys.Quit):
		m.commandBar.Deactivate()
		return m, nil

	default:
		// Forward input to command bar
		m.commandBar.Update(msg)
		return m, nil
	}
}

// processCommand processes an executed command
func (m Model) processCommand(command string) (tea.Model, tea.Cmd) {
	// Add command to logs
	m.logsViewer.AddLog("[CMD] Executed: " + command)

	// Process specific commands
	switch command {
	case ":status":
		// Retrieve MCF status from client
		status, err := m.mcfClient.GetStatus()
		if err != nil {
			m.logsViewer.AddLog("[ERROR] Failed to retrieve MCF status: " + err.Error())
		} else {
			m.logsViewer.AddLog("[INFO] MCF Status: " + status)
		}

	case ":logs":
		m.navigation.SetActiveTab(1) // Logs is index 1
		m.currentView = ViewLogs

	case ":help":
		m.navigation.SetActiveTab(2) // Help is index 2
		m.currentView = ViewHelp

	case ":quit":
		m.quitting = true
		return m, tea.Quit

	case ":config":
		// Load configuration
		config, err := m.mcfClient.LoadConfig()
		if err != nil {
			m.logsViewer.AddLog("[ERROR] Failed to load config: " + err.Error())
		} else {
			m.logsViewer.AddLog("[INFO] Config loaded: " + config)
		}

	case ":refresh":
		// Trigger data refresh
		err := m.mcfClient.Refresh()
		if err != nil {
			m.logsViewer.AddLog("[ERROR] Refresh failed: " + err.Error())
		} else {
			m.logsViewer.AddLog("[INFO] Data refreshed successfully")
		}

	case ":export":
		// Export current dashboard data
		exportPath, err := m.dashboard.ExportData()
		if err != nil {
			m.logsViewer.AddLog("[ERROR] Export failed: " + err.Error())
		} else {
			m.logsViewer.AddLog("[INFO] Data exported to: " + exportPath)
		}

	default:
		// Advanced command parsing with argument support
		parts := strings.Split(command, " ")
		switch parts[0] {
		case ":search":
			if len(parts) > 1 {
				searchResults, err := m.mcfClient.Search(parts[1])
				if err != nil {
					m.logsViewer.AddLog("[ERROR] Search failed: " + err.Error())
				} else {
					m.logsViewer.AddLog("[INFO] Search results: " + strings.Join(searchResults, ", "))
				}
			} else {
				m.logsViewer.AddLog("[ERROR] :search requires a search term")
			}

		default:
			m.logsViewer.AddLog("[ERROR] Unknown command: " + command)
		}
	}

	return m, nil
}

