	scroll int
}

// NewLogsViewer creates a new logs viewer component
func NewLogsViewer() *LogsViewer {
	return &LogsViewer{
		logs: []string{
			"[2025-08-31 14:30:15] [INFO] MCF TUI started successfully",
			"[2025-08-31 14:30:15] [INFO] Serena connection established", 
			"[2025-08-31 14:30:15] [INFO] Configuration loaded from ~/.mcf/config.yaml",
			"[2025-08-31 14:30:16] [DEBUG] Dashboard view initialized",
			"[2025-08-31 14:30:16] [INFO] Ready for user input",
			"[2025-08-31 14:30:20] [DEBUG] User switched to logs view",
			"[2025-08-31 14:30:25] [INFO] MCF client connection verified",
			"[2025-08-31 14:30:30] [DEBUG] UI refresh cycle completed",
		},
		scroll: 0,
	}
}

// SetSize updates the logs viewer dimensions
func (l *LogsViewer) SetSize(width, height int) {
	l.width = width
	l.height = height
}

// AddLog adds a new log entry
func (l *LogsViewer) AddLog(logEntry string) {
	l.logs = append(l.logs, logEntry)

	// Auto-scroll to bottom for new entries
	maxVisible := l.height - 6 // Account for borders and headers
	if len(l.logs) > maxVisible {
		l.scroll = len(l.logs) - maxVisible
	}
}

// ScrollUp scrolls the log view up
func (l *LogsViewer) ScrollUp() {
	if l.scroll > 0 {
		l.scroll--
	}
}

// ScrollDown scrolls the log view down
func (l *LogsViewer) ScrollDown() {
	maxScroll := len(l.logs) - (l.height - 6)
	if maxScroll < 0 {
		maxScroll = 0
	}
	if l.scroll < maxScroll {
		l.scroll++
	}
}

// Render renders the logs viewer
func (l *LogsViewer) Render() string {
	if l.width <= 0 || l.height <= 0 {
		return "Initializing logs viewer..."
	}

	// Header
	header := Styles.Header.Render("📋 MCF Logs Viewer")

	// Calculate visible logs
	maxVisible := l.height - 6 // Account for borders and headers
	visibleLogs := l.getVisibleLogs(maxVisible)

	// Format log entries
	var logLines []string
	for i, log := range visibleLogs {
		if i == len(visibleLogs)-1 {
			// Highlight the most recent log
			logLines = append(logLines, 
				lipgloss.NewStyle().
					Foreground(Colors.Success).
					Render(log))
		} else {
			logLines = append(logLines, log)
		}
	}

	// Join log lines
	logsContent := strings.Join(logLines, "\n")

	// Create scrollable log area
	logArea := Styles.Body.
		Border(lipgloss.RoundedBorder()).
		BorderForeground(Colors.Secondary).
		Width(l.width - 6).
		Height(maxVisible).
		Render(logsContent)

	// Status bar
	totalLogs := len(l.logs)
	statusText := lipgloss.NewStyle().
		Foreground(Colors.Muted).
		Render(fmt.Sprintf("📊 Total logs: %s | Use ↑/↓ to scroll, tab to switch views",
			lipgloss.NewStyle().Foreground(Colors.Accent).Render(fmt.Sprintf("%d", totalLogs))))

	// Combine all sections
	content := lipgloss.JoinVertical(
		lipgloss.Left,
		header,
		"",
		logArea,
		"",
		statusText,
	)

	return ViewBox(content, l.width, l.height)
}

// getVisibleLogs returns the logs that should be visible based on scroll position
func (l *LogsViewer) getVisibleLogs(maxVisible int) []string {
	if len(l.logs) == 0 {
		return []string{"No logs available"}
	}

	start := l.scroll
	end := start + maxVisible

	if end > len(l.logs) {
		end = len(l.logs)
	}

	if start >= len(l.logs) {
		start = len(l.logs) - 1
		if start < 0 {
			start = 0
		}
	}

	return l.logs[start:end]
}

