package app

import (
	"time"

	"github.com/charmbracelet/bubbles/key"
	tea "github.com/charmbracelet/bubbletea"
	"github.com/charmbracelet/lipgloss"

	"mcf-tui/internal/ui"
	"mcf-tui/internal/mcf"
)

// ViewState represents the current active view
type ViewState int

const (
	ViewDashboard ViewState = iota
	ViewLogs
	ViewHelp
)

// Model represents the root application state
type Model struct {
	// Current view state
	currentView ViewState

	// UI dimensions
	width  int
	height int

	// Application state
	ready    bool
	quitting bool
	err      error

	// Last update time for performance tracking
	lastUpdate time.Time

	// Key bindings
	keys KeyMap

	// UI components
	navigation *ui.Navigation
	dashboard  *ui.Dashboard
	logsViewer *ui.LogsViewer
	helpViewer *ui.HelpViewer
	commandBar *ui.CommandBar

	// MCF client
	mcfClient *mcf.Client
}

// KeyMap defines the key bindings for the application
type KeyMap struct {
	Tab     key.Binding
	Quit    key.Binding
	Help    key.Binding
	Enter   key.Binding
	Command key.Binding
}

// DefaultKeyMap returns the default key bindings
func DefaultKeyMap() KeyMap {
	return KeyMap{
		Tab: key.NewBinding(
			key.WithKeys("tab"),
			key.WithHelp("tab", "switch view"),
		),
		Quit: key.NewBinding(
			key.WithKeys("q", "esc", "ctrl+c"),
			key.WithHelp("q", "quit"),
		),
		Help: key.NewBinding(
			key.WithKeys("?"),
			key.WithHelp("?", "help"),
		),
		Enter: key.NewBinding(
			key.WithKeys("enter"),
			key.WithHelp("enter", "execute"),
		),
		Command: key.NewBinding(
			key.WithKeys(":"),
			key.WithHelp(":", "command mode"),
		),
	}
}

// NewModel creates a new application model
func NewModel() Model {
	return Model{
		currentView: ViewDashboard,
		ready:       false,
		quitting:    false,
		lastUpdate:  time.Now(),
		keys:        DefaultKeyMap(),
		navigation:  ui.NewNavigation(),
		dashboard:   ui.NewDashboard(),
		logsViewer:  ui.NewLogsViewer(),
		helpViewer:  ui.NewHelpViewer(),
		commandBar:  ui.NewCommandBar(),
		mcfClient:   mcf.NewClient("http://localhost:24282"),
	}
}

// Init initializes the application
func (m Model) Init() tea.Cmd {
	return nil
}

// View renders the application
func (m Model) View() string {
	if m.err != nil {
		return lipgloss.NewStyle().
			Foreground(lipgloss.Color("9")).
			Render("Error: " + m.err.Error())
	}

	if !m.ready {
		return "Loading MCF TUI..."
	}

	// Update component sizes
	contentHeight := m.height - 5 // Reserve space for navigation and command bar
	m.navigation.SetWidth(m.width)
	m.dashboard.SetSize(m.width, contentHeight)
	m.logsViewer.SetSize(m.width, contentHeight)
	m.helpViewer.SetSize(m.width, contentHeight)
	m.commandBar.SetWidth(m.width)

	// Render navigation
	navBar := m.navigation.Render()

	// Render current view content
	var content string
	switch m.currentView {
	case ViewDashboard:
		content = m.dashboard.Render()
	case ViewLogs:
		content = m.logsViewer.Render()
	case ViewHelp:
		content = m.helpViewer.Render()
	default:
		content = "Unknown view"
	}

	// Render command bar
	commandBar := m.commandBar.Render()

	// Combine navigation, content, and command bar
	return lipgloss.JoinVertical(
		lipgloss.Left,
		navBar,
		content,
		commandBar,
	)
}

// dashboardView renders the main dashboard (now handled by UI component)
func (m Model) dashboardView() string {
	return m.dashboard.Render()
}

// These view methods are now handled by UI components

package app

import (
	"strings"

	"github.com/charmbracelet/bubbles/key"
	tea "github.com/charmbracelet/bubbletea"
)

// Update handles all application state updates
func (m Model) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {

	case tea.WindowSizeMsg:
		m.width = msg.Width
		m.height = msg.Height
		if !m.ready {
			m.ready = true
		}
		return m, nil

	case tea.KeyMsg:
		return m.handleKeyPress(msg)

	case errMsg:
		m.err = msg
		return m, nil

	default:
		// Update command bar with any message
		m.commandBar.Update(msg)
		return m, nil
	}
}

// errMsg wraps errors for the tea.Msg interface
type errMsg error

// handleKeyPress processes keyboard input
func (m Model) handleKeyPress(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	// If command bar is active, handle its input first
	if m.commandBar.IsActive() {
		return m.handleCommandBarInput(msg)
	}

	// Global key bindings
	switch {
	case key.Matches(msg, m.keys.Quit):
		m.quitting = true
		return m, tea.Quit

	case key.Matches(msg, m.keys.Command):
		m.commandBar.Activate()
		return m, nil

	case key.Matches(msg, m.keys.Tab):
		m.navigation.NextTab()
		m.currentView = ViewState(m.navigation.GetActiveTab())
		return m, nil

	case key.Matches(msg, m.keys.Help):
		m.navigation.SetActiveTab(2) // Help is index 2
		m.currentView = ViewHelp
		return m, nil
	}

	// View-specific key handling
	switch m.currentView {
	case ViewDashboard:
		return m.handleDashboardKeys(msg)
	case ViewLogs:
		return m.handleLogsKeys(msg)
	case ViewHelp:
		return m.handleHelpKeys(msg)
	}

	return m, nil
}

// nextView returns the next view in the cycle
func (m Model) nextView() ViewState {
	switch m.currentView {
	case ViewDashboard:
		return ViewLogs
	case ViewLogs:
		return ViewHelp
	case ViewHelp:
		return ViewDashboard
	default:
		return ViewDashboard
	}
}

// handleDashboardKeys handles key presses in dashboard view
func (m Model) handleDashboardKeys(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	// Dashboard-specific key handling will be added here
	return m, nil
}

// handleLogsKeys handles key presses in logs view
func (m Model) handleLogsKeys(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	// Handle search input when focused
	if m.logsViewer.searchInput.Focused() {
		var cmd tea.Cmd
		m.logsViewer.searchInput, cmd = m.logsViewer.searchInput.Update(msg)

		switch msg.Type {
		case tea.KeyEnter:
			// Perform search
			m.logsViewer.performSearch(m.logsViewer.searchInput.Value())
			m.logsViewer.searchInput.Blur()
		case tea.KeyEsc:
			// Cancel search
			m.logsViewer.searchInput.Blur()
			m.logsViewer.searchQuery = ""
		}
		return m, cmd
	}

	switch msg.String() {
	case "up", "k":
		m.logsViewer.ScrollUp()
		return m, nil
	case "down", "j":
		m.logsViewer.ScrollDown()
		return m, nil
	case "pgup":
		m.logsViewer.PageUp()
		return m, nil
	case "pgdown":
		m.logsViewer.PageDown()
		return m, nil
	case "home":
		m.logsViewer.ScrollToTop()
		return m, nil
	case "end":
		m.logsViewer.ScrollToBottom()
		return m, nil
	case "/":
		// Activate search mode
		m.logsViewer.ToggleSearch()
		return m, nil
	case "n":
		// Next search result
		if m.logsViewer.searchQuery != "" {
			m.logsViewer.NavigateSearchResults(true)
		}
		return m, nil
	case "N":
		// Previous search result
		if m.logsViewer.searchQuery != "" {
			m.logsViewer.NavigateSearchResults(false)
		}
		return m, nil
	case "ctrl+j":
		// Scroll down relative to selected line
		m.logsViewer.SelectLineRelative(1)
		return m, nil
	case "ctrl+k":
		// Scroll up relative to selected line
		m.logsViewer.SelectLineRelative(-1)
		return m, nil
	}
	return m, nil
}

// handleHelpKeys handles key presses in help view
func (m Model) handleHelpKeys(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	// Help-specific key handling will be added here
	return m, nil
}

// handleCommandBarInput handles input when command bar is active
func (m Model) handleCommandBarInput(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	switch {
	case key.Matches(msg, m.keys.Enter):
		command, err := m.commandBar.ExecuteCommand()
		if err != nil {
			m.logsViewer.AddLog("[ERROR] " + err.Error())
			return m, nil
		}
		return m.processCommand(command)

	case key.Matches(msg, m.keys.Quit):
		m.commandBar.Deactivate()
		return m, nil

	default:
		// Forward input to command bar
		m.commandBar.Update(msg)
		return m, nil
	}
}

// processCommand processes an executed command
func (m Model) processCommand(command string) (tea.Model, tea.Cmd) {
	// Add command to logs
	m.logsViewer.AddLog("[CMD] Executed: " + command)

	// Process specific commands
	switch command {
	case ":status":
		// Retrieve MCF status from client
		status, err := m.mcfClient.GetStatus()
		if err != nil {
			m.logsViewer.AddLog("[ERROR] Failed to retrieve MCF status: " + err.Error())
		} else {
			m.logsViewer.AddLog("[INFO] MCF Status: " + status)
		}

	case ":logs":
		m.navigation.SetActiveTab(1) // Logs is index 1
		m.currentView = ViewLogs

	case ":help":
		m.navigation.SetActiveTab(2) // Help is index 2
		m.currentView = ViewHelp

	case ":quit":
		m.quitting = true
		return m, tea.Quit

	case ":config":
		// Load configuration
		config, err := m.mcfClient.LoadConfig()
		if err != nil {
			m.logsViewer.AddLog("[ERROR] Failed to load config: " + err.Error())
		} else {
			m.logsViewer.AddLog("[INFO] Config loaded: " + config)
		}

	case ":refresh":
		// Trigger data refresh
		err := m.mcfClient.Refresh()
		if err != nil {
			m.logsViewer.AddLog("[ERROR] Refresh failed: " + err.Error())
		} else {
			m.logsViewer.AddLog("[INFO] Data refreshed successfully")
		}

	case ":export":
		// Export current dashboard data
		exportPath, err := m.dashboard.ExportData()
		if err != nil {
			m.logsViewer.AddLog("[ERROR] Export failed: " + err.Error())
		} else {
			m.logsViewer.AddLog("[INFO] Data exported to: " + exportPath)
		}

	default:
		// Advanced command parsing with argument support
		parts := strings.Split(command, " ")
		switch parts[0] {
		case ":search":
			if len(parts) > 1 {
				searchResults, err := m.mcfClient.Search(parts[1])
				if err != nil {
					m.logsViewer.AddLog("[ERROR] Search failed: " + err.Error())
				} else {
					m.logsViewer.AddLog("[INFO] Search results: " + strings.Join(searchResults, ", "))
				}
			} else {
				m.logsViewer.AddLog("[ERROR] :search requires a search term")
			}

		default:
			m.logsViewer.AddLog("[ERROR] Unknown command: " + command)
		}
	}

	return m, nil
}

