package errors

import (
	"context"
	"fmt"
	"time"
)

// ErrorType represents the category of error
type ErrorType int

const (
	ErrorTypeUnknown ErrorType = iota
	ErrorTypeValidation
	ErrorTypeNetwork
	ErrorTypeConfiguration
	ErrorTypeCommand
	ErrorTypeAuthentication
	ErrorTypePermission
	ErrorTypeTimeout
	ErrorTypeSystemResource
)

// Severity represents the severity level of an error
type Severity int

const (
	SeverityInfo Severity = iota
	SeverityWarning
	SeverityError
	SeverityCritical
)

// AppError represents a structured application error
type AppError struct {
	Type      ErrorType
	Severity  Severity
	Code      string
	Message   string
	Details   string
	Cause     error
	Timestamp time.Time
	Context   map[string]interface{}
	Retryable bool
	UserMsg   string // User-friendly message
}

// Error implements the error interface
func (e *AppError) Error() string {
	if e.Details != "" {
		return fmt.Sprintf("%s: %s", e.Message, e.Details)
	}
	return e.Message
}

// Unwrap returns the underlying error
func (e *AppError) Unwrap() error {
	return e.Cause
}

// IsRetryable returns whether the error can be retried
func (e *AppError) IsRetryable() bool {
	return e.Retryable
}

// GetUserMessage returns a user-friendly error message
func (e *AppError) GetUserMessage() string {
	if e.UserMsg != "" {
		return e.UserMsg
	}
	return e.Message
}

// WithContext adds context information to the error
func (e *AppError) WithContext(key string, value interface{}) *AppError {
	if e.Context == nil {
		e.Context = make(map[string]interface{})
	}
	e.Context[key] = value
	return e
}

// NewValidationError creates a new validation error
func NewValidationError(message, details string) *AppError {
	return &AppError{
		Type:      ErrorTypeValidation,
		Severity:  SeverityError,
		Code:      "VALIDATION_ERROR",
		Message:   message,
		Details:   details,
		Timestamp: time.Now(),
		UserMsg:   fmt.Sprintf("Invalid input: %s", details),
		Retryable: false,
	}
}

// NewNetworkError creates a new network error
func NewNetworkError(message string, cause error, retryable bool) *AppError {
	return &AppError{
		Type:      ErrorTypeNetwork,
		Severity:  SeverityError,
		Code:      "NETWORK_ERROR",
		Message:   message,
		Cause:     cause,
		Timestamp: time.Now(),
		UserMsg:   "Network connection issue. Please check your connection and try again.",
		Retryable: retryable,
	}
}

// NewConfigurationError creates a new configuration error
func NewConfigurationError(message, details string) *AppError {
	return &AppError{
		Type:      ErrorTypeConfiguration,
		Severity:  SeverityError,
		Code:      "CONFIG_ERROR",
		Message:   message,
		Details:   details,
		Timestamp: time.Now(),
		UserMsg:   "Configuration issue. Please check your settings.",
		Retryable: false,
	}
}

// NewCommandError creates a new command error
func NewCommandError(message, command string) *AppError {
	return &AppError{
		Type:      ErrorTypeCommand,
		Severity:  SeverityError,
		Code:      "COMMAND_ERROR",
		Message:   message,
		Details:   fmt.Sprintf("Command: %s", command),
		Timestamp: time.Now(),
		UserMsg:   fmt.Sprintf("Command failed: %s", message),
		Retryable: false,
	}
}

// NewTimeoutError creates a new timeout error
func NewTimeoutError(operation string, duration time.Duration) *AppError {
	return &AppError{
		Type:      ErrorTypeTimeout,
		Severity:  SeverityWarning,
		Code:      "TIMEOUT_ERROR",
		Message:   fmt.Sprintf("Operation timed out: %s", operation),
		Details:   fmt.Sprintf("Timeout after %v", duration),
		Timestamp: time.Now(),
		UserMsg:   fmt.Sprintf("Operation timed out after %v. Please try again.", duration),
		Retryable: true,
	}
}

// NewSystemResourceError creates a new system resource error
func NewSystemResourceError(resource, message string) *AppError {
	return &AppError{
		Type:      ErrorTypeSystemResource,
		Severity:  SeverityCritical,
		Code:      "RESOURCE_ERROR",
		Message:   fmt.Sprintf("System resource error: %s", resource),
		Details:   message,
		Timestamp: time.Now(),
		UserMsg:   "System resource issue. Please check system status.",
		Retryable: false,
	}
}

// IsRetryableError checks if an error is retryable
func IsRetryableError(err error) bool {
	if appErr, ok := err.(*AppError); ok {
		return appErr.IsRetryable()
	}

	// Check for common retryable errors
	if err == context.DeadlineExceeded || err == context.Canceled {
		return true
	}

	return false
}

// GetErrorType extracts the error type from an error
func GetErrorType(err error) ErrorType {
	if appErr, ok := err.(*AppError); ok {
		return appErr.Type
	}
	return ErrorTypeUnknown
}

// GetSeverity extracts the severity from an error
func GetSeverity(err error) Severity {
	if appErr, ok := err.(*AppError); ok {
		return appErr.Severity
	}
	return SeverityError
}

