package errors

import (
	"context"
	"fmt"
	"log/slog"
	"sync"
	"time"
)

// ErrorHandler provides centralized error handling and recovery
type ErrorHandler struct {
	logger        *slog.Logger
	retryConfig   RetryConfig
	errorChan     chan *AppError
	subscribers   []ErrorSubscriber
	mu            sync.RWMutex
	errorStats    map[ErrorType]int
	lastErrors    []*AppError
	maxLastErrors int
}

// RetryConfig defines retry behavior
type RetryConfig struct {
	MaxAttempts   int
	InitialDelay  time.Duration
	MaxDelay      time.Duration
	BackoffFactor float64
}

// ErrorSubscriber receives error notifications
type ErrorSubscriber interface {
	OnError(err *AppError)
}

// DefaultRetryConfig returns default retry configuration
func DefaultRetryConfig() RetryConfig {
	return RetryConfig{
		MaxAttempts:   3,
		InitialDelay:  1 * time.Second,
		MaxDelay:      30 * time.Second,
		BackoffFactor: 2.0,
	}
}

// NewErrorHandler creates a new error handler
func NewErrorHandler(logger *slog.Logger) *ErrorHandler {
	if logger == nil {
		logger = slog.Default()
	}

	return &ErrorHandler{
		logger:        logger,
		retryConfig:   DefaultRetryConfig(),
		errorChan:     make(chan *AppError, 100),
		subscribers:   make([]ErrorSubscriber, 0),
		errorStats:    make(map[ErrorType]int),
		lastErrors:    make([]*AppError, 0),
		maxLastErrors: 50,
	}
}

// Subscribe adds an error subscriber
func (h *ErrorHandler) Subscribe(subscriber ErrorSubscriber) {
	h.mu.Lock()
	defer h.mu.Unlock()
	h.subscribers = append(h.subscribers, subscriber)
}

// Handle processes an error through the centralized handler
func (h *ErrorHandler) Handle(err error) *AppError {
	var appErr *AppError

	// Convert to AppError if not already
	if ae, ok := err.(*AppError); ok {
		appErr = ae
	} else {
		appErr = &AppError{
			Type:      ErrorTypeUnknown,
			Severity:  SeverityError,
			Code:      "UNKNOWN_ERROR",
			Message:   err.Error(),
			Cause:     err,
			Timestamp: time.Now(),
			UserMsg:   "An unexpected error occurred",
			Retryable: false,
		}
	}

	// Update statistics
	h.updateStats(appErr)

	// Log the error
	h.logError(appErr)

	// Notify subscribers
	h.notifySubscribers(appErr)

	// Store in recent errors
	h.addToRecentErrors(appErr)

	return appErr
}

// HandleWithContext processes an error with additional context
func (h *ErrorHandler) HandleWithContext(err error, ctx map[string]interface{}) *AppError {
	appErr := h.Handle(err)

	// Add context information
	for k, v := range ctx {
		appErr.WithContext(k, v)
	}

	return appErr
}

// Retry executes an operation with retry logic
func (h *ErrorHandler) Retry(ctx context.Context, operation func() error, retryable func(error) bool) error {
	var lastErr error
	delay := h.retryConfig.InitialDelay

	for attempt := 0; attempt < h.retryConfig.MaxAttempts; attempt++ {
		select {
		case <-ctx.Done():
			return NewTimeoutError("retry operation", time.Since(time.Now()))
		default:
		}

		err := operation()
		if err == nil {
			return nil
		}

		lastErr = err

		// Check if error is retryable
		if retryable != nil && !retryable(err) {
			break
		}

		if !IsRetryableError(err) {
			break
		}

		// Don't sleep on the last attempt
		if attempt < h.retryConfig.MaxAttempts-1 {
			h.logger.Warn("Retrying operation",
				slog.Int("attempt", attempt+1),
				slog.String("error", err.Error()),
				slog.Duration("delay", delay))

			select {
			case <-ctx.Done():
				return NewTimeoutError("retry operation", time.Since(time.Now()))
			case <-time.After(delay):
			}

			// Exponential backoff
			delay = time.Duration(float64(delay) * h.retryConfig.BackoffFactor)
			if delay > h.retryConfig.MaxDelay {
				delay = h.retryConfig.MaxDelay
			}
		}
	}

	return h.Handle(fmt.Errorf("operation failed after %d attempts: %w", h.retryConfig.MaxAttempts, lastErr))
}

// Recover recovers from a panic and converts it to an AppError
func (h *ErrorHandler) Recover() {
	if r := recover(); r != nil {
		var err error
		if e, ok := r.(error); ok {
			err = e
		} else {
			err = fmt.Errorf("panic: %v", r)
		}

		appErr := &AppError{
			Type:      ErrorTypeSystemResource,
			Severity:  SeverityCritical,
			Code:      "PANIC_RECOVERY",
			Message:   "Application panic recovered",
			Details:   err.Error(),
			Timestamp: time.Now(),
			UserMsg:   "An unexpected error occurred. The application has recovered.",
			Retryable: false,
		}

		h.Handle(appErr)
	}
}

// GetStats returns error statistics
func (h *ErrorHandler) GetStats() map[ErrorType]int {
	h.mu.RLock()
	defer h.mu.RUnlock()

	stats := make(map[ErrorType]int)
	for k, v := range h.errorStats {
		stats[k] = v
	}
	return stats
}

// GetRecentErrors returns recent errors
func (h *ErrorHandler) GetRecentErrors() []*AppError {
	h.mu.RLock()
	defer h.mu.RUnlock()

	errors := make([]*AppError, len(h.lastErrors))
	copy(errors, h.lastErrors)
	return errors
}

// ClearStats clears error statistics
func (h *ErrorHandler) ClearStats() {
	h.mu.Lock()
	defer h.mu.Unlock()

	h.errorStats = make(map[ErrorType]int)
	h.lastErrors = make([]*AppError, 0)
}

// updateStats updates error statistics
func (h *ErrorHandler) updateStats(err *AppError) {
	h.mu.Lock()
	defer h.mu.Unlock()
	h.errorStats[err.Type]++
}

// logError logs the error with appropriate level
func (h *ErrorHandler) logError(err *AppError) {
	attrs := []slog.Attr{
		slog.String("type", h.errorTypeToString(err.Type)),
		slog.String("code", err.Code),
		slog.String("message", err.Message),
		slog.Time("timestamp", err.Timestamp),
	}

	if err.Details != "" {
		attrs = append(attrs, slog.String("details", err.Details))
	}

	if err.Cause != nil {
		attrs = append(attrs, slog.String("cause", err.Cause.Error()))
	}

	// Add context if available
	for k, v := range err.Context {
		attrs = append(attrs, slog.Any(k, v))
	}

	switch err.Severity {
	case SeverityInfo:
		h.logger.LogAttrs(context.Background(), slog.LevelInfo, "Application error", attrs...)
	case SeverityWarning:
		h.logger.LogAttrs(context.Background(), slog.LevelWarn, "Application warning", attrs...)
	case SeverityError:
		h.logger.LogAttrs(context.Background(), slog.LevelError, "Application error", attrs...)
	case SeverityCritical:
		h.logger.LogAttrs(context.Background(), slog.LevelError, "Critical application error", attrs...)
	}
}

// notifySubscribers notifies all error subscribers
func (h *ErrorHandler) notifySubscribers(err *AppError) {
	h.mu.RLock()
	defer h.mu.RUnlock()

	for _, subscriber := range h.subscribers {
		go func(s ErrorSubscriber) {
			defer h.Recover()
			s.OnError(err)
		}(subscriber)
	}
}

// addToRecentErrors adds error to recent errors list
func (h *ErrorHandler) addToRecentErrors(err *AppError) {
	h.mu.Lock()
	defer h.mu.Unlock()

	h.lastErrors = append(h.lastErrors, err)
	if len(h.lastErrors) > h.maxLastErrors {
		h.lastErrors = h.lastErrors[1:]
	}
}

// errorTypeToString converts ErrorType to string
func (h *ErrorHandler) errorTypeToString(t ErrorType) string {
	switch t {
	case ErrorTypeValidation:
		return "validation"
	case ErrorTypeNetwork:
		return "network"
	case ErrorTypeConfiguration:
		return "configuration"
	case ErrorTypeCommand:
		return "command"
	case ErrorTypeAuthentication:
		return "authentication"
	case ErrorTypePermission:
		return "permission"
	case ErrorTypeTimeout:
		return "timeout"
	case ErrorTypeSystemResource:
		return "system_resource"
	default:
		return "unknown"
	}
}

