package validation

import (
	"fmt"
	"net/url"
	"regexp"
	"strconv"
	"strings"

	"mcf-tui/internal/errors"
)

// Validator provides input validation functionality
type Validator struct {
	rules map[string][]ValidationRule
}

// ValidationRule represents a single validation rule
type ValidationRule struct {
	Name      string
	Validator func(value interface{}) error
	Message   string
}

// ValidationResult contains validation results
type ValidationResult struct {
	Valid  bool
	Errors []string
	Field  string
}

// NewValidator creates a new validator instance
func NewValidator() *Validator {
	return &Validator{
		rules: make(map[string][]ValidationRule),
	}
}

// AddRule adds a validation rule for a field
func (v *Validator) AddRule(field string, rule ValidationRule) {
	v.rules[field] = append(v.rules[field], rule)
}

// Validate validates a field value against its rules
func (v *Validator) Validate(field string, value interface{}) *ValidationResult {
	result := &ValidationResult{
		Valid: true,
		Field: field,
	}

	rules, exists := v.rules[field]
	if !exists {
		return result
	}

	for _, rule := range rules {
		if err := rule.Validator(value); err != nil {
			result.Valid = false
			if rule.Message != "" {
				result.Errors = append(result.Errors, rule.Message)
			} else {
				result.Errors = append(result.Errors, err.Error())
			}
		}
	}

	return result
}

// ValidateAll validates multiple fields
func (v *Validator) ValidateAll(data map[string]interface{}) map[string]*ValidationResult {
	results := make(map[string]*ValidationResult)

	for field, value := range data {
		results[field] = v.Validate(field, value)
	}

	return results
}

// HasErrors checks if any validation results have errors
func HasErrors(results map[string]*ValidationResult) bool {
	for _, result := range results {
		if !result.Valid {
			return true
		}
	}
	return false
}

// GetErrorMessages extracts all error messages from validation results
func GetErrorMessages(results map[string]*ValidationResult) []string {
	var messages []string
	for field, result := range results {
		if !result.Valid {
			for _, err := range result.Errors {
				messages = append(messages, fmt.Sprintf("%s: %s", field, err))
			}
		}
	}
	return messages
}

// Common validation rules

// Required validates that a value is not empty
func Required() ValidationRule {
	return ValidationRule{
		Name: "required",
		Validator: func(value interface{}) error {
			if value == nil {
				return fmt.Errorf("field is required")
			}

			switch v := value.(type) {
			case string:
				if strings.TrimSpace(v) == "" {
					return fmt.Errorf("field is required")
				}
			case []string:
				if len(v) == 0 {
					return fmt.Errorf("field is required")
				}
			default:
				// For other types, just check if nil
				if value == nil {
					return fmt.Errorf("field is required")
				}
			}
			return nil
		},
		Message: "This field is required",
	}
}

// MinLength validates minimum string length
func MinLength(min int) ValidationRule {
	return ValidationRule{
		Name: "minLength",
		Validator: func(value interface{}) error {
			if str, ok := value.(string); ok {
				if len(str) < min {
					return fmt.Errorf("minimum length is %d characters", min)
				}
			}
			return nil
		},
		Message: fmt.Sprintf("Minimum length is %d characters", min),
	}
}

// MaxLength validates maximum string length
func MaxLength(max int) ValidationRule {
	return ValidationRule{
		Name: "maxLength",
		Validator: func(value interface{}) error {
			if str, ok := value.(string); ok {
				if len(str) > max {
					return fmt.Errorf("maximum length is %d characters", max)
				}
			}
			return nil
		},
		Message: fmt.Sprintf("Maximum length is %d characters", max),
	}
}

// Pattern validates against a regular expression
func Pattern(pattern, message string) ValidationRule {
	regex := regexp.MustCompile(pattern)
	return ValidationRule{
		Name: "pattern",
		Validator: func(value interface{}) error {
			if str, ok := value.(string); ok {
				if !regex.MatchString(str) {
					return fmt.Errorf("does not match required pattern")
				}
			}
			return nil
		},
		Message: message,
	}
}

// URL validates that a string is a valid URL
func URL() ValidationRule {
	return ValidationRule{
		Name: "url",
		Validator: func(value interface{}) error {
			if str, ok := value.(string); ok {
				if _, err := url.Parse(str); err != nil {
					return fmt.Errorf("invalid URL format")
				}
				if !strings.HasPrefix(str, "http://") && !strings.HasPrefix(str, "https://") {
					return fmt.Errorf("URL must start with http:// or https://")
				}
			}
			return nil
		},
		Message: "Must be a valid URL",
	}
}

// Port validates that a value is a valid port number
func Port() ValidationRule {
	return ValidationRule{
		Name: "port",
		Validator: func(value interface{}) error {
			var port int
			var err error

			switch v := value.(type) {
			case string:
				port, err = strconv.Atoi(v)
				if err != nil {
					return fmt.Errorf("must be a valid port number")
				}
			case int:
				port = v
			default:
				return fmt.Errorf("must be a number")
			}

			if port < 1 || port > 65535 {
				return fmt.Errorf("port must be between 1 and 65535")
			}
			return nil
		},
		Message: "Must be a valid port number (1-65535)",
	}
}

// Range validates that a numeric value is within a range
func Range(min, max int) ValidationRule {
	return ValidationRule{
		Name: "range",
		Validator: func(value interface{}) error {
			var num int
			var err error

			switch v := value.(type) {
			case string:
				num, err = strconv.Atoi(v)
				if err != nil {
					return fmt.Errorf("must be a valid number")
				}
			case int:
				num = v
			default:
				return fmt.Errorf("must be a number")
			}

			if num < min || num > max {
				return fmt.Errorf("must be between %d and %d", min, max)
			}
			return nil
		},
		Message: fmt.Sprintf("Must be between %d and %d", min, max),
	}
}

// CommandValidator validates MCF TUI commands
type CommandValidator struct {
	validator *Validator
}

// NewCommandValidator creates a command validator
func NewCommandValidator() *CommandValidator {
	v := NewValidator()

	// Command format validation
	v.AddRule("command", ValidationRule{
		Name: "command_format",
		Validator: func(value interface{}) error {
			if str, ok := value.(string); ok {
				str = strings.TrimSpace(str)
				if str == "" {
					return errors.NewValidationError("empty command", "Command cannot be empty")
				}
				if !strings.HasPrefix(str, ":") {
					return errors.NewValidationError("invalid command format", "Commands must start with ':'")
				}
				if len(str) == 1 {
					return errors.NewValidationError("incomplete command", "Command name is required after ':'")
				}
			}
			return nil
		},
		Message: "Commands must start with ':' and contain a command name",
	})

	return &CommandValidator{validator: v}
}

// ValidateCommand validates a command string
func (cv *CommandValidator) ValidateCommand(command string) error {
	result := cv.validator.Validate("command", command)
	if !result.Valid {
		return errors.NewValidationError("invalid command", strings.Join(result.Errors, "; "))
	}

	// Additional command-specific validation
	parts := strings.Fields(strings.TrimSpace(command))
	if len(parts) == 0 {
		return errors.NewValidationError("empty command", "Command cannot be empty")
	}

	cmdName := strings.TrimPrefix(parts[0], ":")
	if err := cv.validateCommandName(cmdName); err != nil {
		return err
	}

	// Validate command arguments
	return cv.validateCommandArgs(cmdName, parts[1:])
}

// validateCommandName validates the command name
func (cv *CommandValidator) validateCommandName(cmdName string) error {
	validCommands := map[string]bool{
		"status":  true,
		"logs":    true,
		"help":    true,
		"quit":    true,
		"config":  true,
		"refresh": true,
		"export":  true,
		"search":  true,
	}

	if !validCommands[cmdName] {
		return errors.NewValidationError("unknown command", 
			fmt.Sprintf("Unknown command '%s'. Type ':help' for available commands", cmdName))
	}

	return nil
}

// validateCommandArgs validates command arguments
func (cv *CommandValidator) validateCommandArgs(cmdName string, args []string) error {
	switch cmdName {
	case "search":
		if len(args) == 0 {
			return errors.NewValidationError("missing search term", "Search command requires a search term")
		}
		if len(args) > 1 {
			return errors.NewValidationError("too many arguments", "Search command accepts only one search term")
		}
		if strings.TrimSpace(args[0]) == "" {
			return errors.NewValidationError("empty search term", "Search term cannot be empty")
		}

	case "status", "logs", "help", "quit", "config", "refresh", "export":
		if len(args) > 0 {
			return errors.NewValidationError("unexpected arguments", 
				fmt.Sprintf("Command '%s' does not accept arguments", cmdName))
		}
	}

	return nil
}

// ConfigValidator validates configuration values
type ConfigValidator struct {
	validator *Validator
}

// NewConfigValidator creates a configuration validator
func NewConfigValidator() *ConfigValidator {
	v := NewValidator()

	// Add configuration validation rules
	v.AddRule("log_level", ValidationRule{
		Name: "log_level",
		Validator: func(value interface{}) error {
			if str, ok := value.(string); ok {
				validLevels := map[string]bool{
					"debug": true, "info": true, "warn": true, "error": true,
				}
				if !validLevels[strings.ToLower(str)] {
					return fmt.Errorf("invalid log level")
				}
			}
			return nil
		},
		Message: "Log level must be one of: debug, info, warn, error",
	})

	v.AddRule("theme", ValidationRule{
		Name: "theme",
		Validator: func(value interface{}) error {
			if str, ok := value.(string); ok {
				validThemes := map[string]bool{
					"default": true, "dark": true, "light": true,
				}
				if !validThemes[strings.ToLower(str)] {
					return fmt.Errorf("invalid theme")
				}
			}
			return nil
		},
		Message: "Theme must be one of: default, dark, light",
	})

	v.AddRule("refresh_rate", Range(100, 10000))
	v.AddRule("serena_url", URL())
	v.AddRule("max_log_lines", Range(10, 10000))

	return &ConfigValidator{validator: v}
}

// ValidateConfig validates configuration data
func (cv *ConfigValidator) ValidateConfig(config map[string]interface{}) error {
	results := cv.validator.ValidateAll(config)

	if HasErrors(results) {
		messages := GetErrorMessages(results)
		return errors.NewConfigurationError("configuration validation failed", 
			strings.Join(messages, "; "))
	}

	return nil
}

