package mcf

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"log/slog"
	"net/http"
	"sync"
	"time"

	"mcf-tui/internal/errors"
	"mcf-tui/internal/validation"
)

// ClientConfig allows configuration of MCF client
type ClientConfig struct {
	BaseURL       string
	Timeout       time.Duration
	RetryAttempts int
	RetryDelay    time.Duration
	Logger        *slog.Logger
}

// Client represents an MCF integration client with advanced features and error handling
type Client struct {
	baseURL        string
	httpClient     *http.Client
	config         ClientConfig
	mu             sync.RWMutex
	lastStatus     *Status
	lastChecksum   string
	errorHandler   *errors.ErrorHandler
	validator      *validation.Validator
	connectionTested bool
	isHealthy       bool
}

// Status represents MCF system status with extended details
type Status struct {
	Version         string    `json:"version"`
	Uptime          string    `json:"uptime"`
	SerenaURL       string    `json:"serena_url"`
	Connected       bool      `json:"connected"`
	LastUpdate      time.Time `json:"last_update"`
	ConfigVersion   string    `json:"config_version,omitempty"`
	SystemLoad      float64   `json:"system_load,omitempty"`
	AvailableMemory uint64    `json:"available_memory,omitempty"`
}

// NewClient creates a new MCF client with enhanced error handling and validation
func NewClient(cfg ClientConfig) *Client {
	if cfg.Timeout == 0 {
		cfg.Timeout = 10 * time.Second
	}
	if cfg.RetryAttempts == 0 {
		cfg.RetryAttempts = 3
	}
	if cfg.RetryDelay == 0 {
		cfg.RetryDelay = 1 * time.Second
	}
	if cfg.Logger == nil {
		cfg.Logger = slog.Default()
	}

	// Validate base URL
	validator := validation.NewValidator()
	validator.AddRule("base_url", validation.URL())

	if result := validator.Validate("base_url", cfg.BaseURL); !result.Valid {
		cfg.Logger.Error("Invalid MCF base URL", slog.String("url", cfg.BaseURL))
	}

	client := &Client{
		baseURL: cfg.BaseURL,
		httpClient: &http.Client{
			Timeout: cfg.Timeout,
			Transport: &http.Transport{
				MaxIdleConns:        10,
				MaxIdleConnsPerHost: 2,
				IdleConnTimeout:     30 * time.Second,
			},
		},
		config:       cfg,
		errorHandler: errors.NewErrorHandler(cfg.Logger),
		validator:    validator,
		isHealthy:    false,
	}

	return client
}

// Simple constructor for backward compatibility
func NewClient(baseURL string) *Client {
	return NewClient(ClientConfig{
		BaseURL: baseURL,
	})
}

// GetStatus retrieves the current MCF system status with comprehensive error handling
func (c *Client) GetStatus(ctx context.Context) (*Status, error) {
	operation := func() error {
		status, err := c.fetchStatus(ctx)
		if err != nil {
			return err
		}

		c.mu.Lock()
		c.lastStatus = status
		c.isHealthy = true
		c.mu.Unlock()

		return nil
	}

	// Use error handler with retry logic
	err := c.errorHandler.Retry(ctx, operation, c.isRetryableError)
	if err != nil {
		c.mu.Lock()
		c.isHealthy = false
		c.mu.Unlock()

		return nil, c.errorHandler.HandleWithContext(err, map[string]interface{}{
			"operation": "get_status",
			"url":       c.baseURL + "/status",
		})
	}

	c.mu.RLock()
	defer c.mu.RUnlock()
	return c.lastStatus, nil
}

// GetStatus with old signature for backward compatibility
func (c *Client) GetStatus() (string, error) {
	ctx := context.Background()
	status, err := c.GetStatus(ctx)
	if err != nil {
		return "", err
	}

	// Format status as string for backward compatibility
	return fmt.Sprintf("Version: %s, Uptime: %s, Connected: %t", 
		status.Version, status.Uptime, status.Connected), nil
}

// fetchStatus performs the actual HTTP request to get system status
func (c *Client) fetchStatus(ctx context.Context) (*Status, error) {
	req, err := http.NewRequestWithContext(ctx, "GET", c.baseURL+"/status", nil)
	if err != nil {
		return nil, errors.NewNetworkError("failed to create status request", err, false)
	}

	resp, err := c.httpClient.Do(req)
	if err != nil {
		// Determine if error is retryable
		retryable := c.isRetryableError(err)
		return nil, errors.NewNetworkError("status request failed", err, retryable)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		body, _ := io.ReadAll(resp.Body)
		err := fmt.Errorf("HTTP %d: %s", resp.StatusCode, string(body))

		// 5xx errors are typically retryable, 4xx are not
		retryable := resp.StatusCode >= 500
		return nil, errors.NewNetworkError("unexpected status code", err, retryable)
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, errors.NewNetworkError("failed to read response body", err, false)
	}

	var status Status
	if err := json.Unmarshal(body, &status); err != nil {
		return nil, errors.NewNetworkError("failed to parse status response", err, false).
			WithContext("response_body", string(body))
	}

	// Validate response data
	if err := c.validateStatusResponse(&status); err != nil {
		return nil, err
	}

	return &status, nil
}

// GetLogs retrieves MCF logs with enhanced error handling
func (c *Client) GetLogs(ctx context.Context, maxLines int) ([]string, error) {
	// Validate input
	if maxLines <= 0 {
		return nil, errors.NewValidationError("invalid max lines", "maxLines must be positive")
	}
	if maxLines > 10000 {
		return nil, errors.NewValidationError("max lines too large", "maxLines cannot exceed 10000")
	}

	req, err := http.NewRequestWithContext(ctx, "GET", c.baseURL+"/logs", nil)
	if err != nil {
		return nil, c.errorHandler.Handle(errors.NewNetworkError("failed to create logs request", err, false))
	}

	q := req.URL.Query()
	q.Add("max_lines", fmt.Sprintf("%d", maxLines))
	req.URL.RawQuery = q.Encode()

	operation := func() error {
		resp, err := c.httpClient.Do(req)
		if err != nil {
			return errors.NewNetworkError("logs request failed", err, c.isRetryableError(err))
		}
		defer resp.Body.Close()

		if resp.StatusCode != http.StatusOK {
			retryable := resp.StatusCode >= 500
			return errors.NewNetworkError(
				fmt.Sprintf("logs request failed with status %d", resp.StatusCode),
				fmt.Errorf("HTTP %d", resp.StatusCode),
				retryable,
			)
		}

		var logs []string
		if err := json.NewDecoder(resp.Body).Decode(&logs); err != nil {
			return errors.NewNetworkError("failed to parse logs", err, false)
		}

		return nil
	}

	err = c.errorHandler.Retry(ctx, operation, c.isRetryableError)
	if err != nil {
		return nil, c.errorHandler.HandleWithContext(err, map[string]interface{}{
			"operation":  "get_logs",
			"max_lines":  maxLines,
			"url":        c.baseURL + "/logs",
		})
	}

	// This is a simplified implementation - in reality, you'd capture the logs in the operation
	return []string{}, nil
}

// ExecuteCommand sends a command to MCF with comprehensive validation and error handling
func (c *Client) ExecuteCommand(ctx context.Context, command string) (string, error) {
	// Validate command
	cmdValidator := validation.NewCommandValidator()
	if err := cmdValidator.ValidateCommand(command); err != nil {
		return "", c.errorHandler.Handle(err)
	}

	payload := struct {
		Command string `json:"command"`
	}{Command: command}

	jsonPayload, err := json.Marshal(payload)
	if err != nil {
		return "", c.errorHandler.Handle(errors.NewCommandError("failed to marshal command payload", command))
	}

	req, err := http.NewRequestWithContext(ctx, "POST", c.baseURL+"/execute",
		bytes.NewBuffer(jsonPayload))
	if err != nil {
		return "", c.errorHandler.Handle(errors.NewNetworkError("failed to create execute request", err, false))
	}
	req.Header.Set("Content-Type", "application/json")

	var result struct {
		Output string `json:"output"`
		Error  string `json:"error,omitempty"`
	}

	operation := func() error {
		resp, err := c.httpClient.Do(req)
		if err != nil {
			return errors.NewNetworkError("command execution failed", err, c.isRetryableError(err))
		}
		defer resp.Body.Close()

		if resp.StatusCode != http.StatusOK {
			body, _ := io.ReadAll(resp.Body)
			retryable := resp.StatusCode >= 500
			return errors.NewNetworkError(
				fmt.Sprintf("command execution failed with status %d", resp.StatusCode),
				fmt.Errorf("HTTP %d: %s", resp.StatusCode, string(body)),
				retryable,
			)
		}

		if err := json.NewDecoder(resp.Body).Decode(&result); err != nil {
			return errors.NewCommandError("failed to parse command result", command)
		}

		if result.Error != "" {
			return errors.NewCommandError(result.Error, command)
		}

		return nil
	}

	err = c.errorHandler.Retry(ctx, operation, c.isRetryableError)
	if err != nil {
		return "", c.errorHandler.HandleWithContext(err, map[string]interface{}{
			"operation": "execute_command",
			"command":   command,
			"url":       c.baseURL + "/execute",
		})
	}

	return result.Output, nil
}

// CheckConnection verifies MCF service connectivity with detailed error reporting
func (c *Client) CheckConnection(ctx context.Context) error {
	c.config.Logger.Debug("Checking MCF connection", slog.String("url", c.baseURL))

	_, err := c.GetStatus(ctx)
	if err != nil {
		c.mu.Lock()
		c.isHealthy = false
		c.connectionTested = true
		c.mu.Unlock()

		return c.errorHandler.HandleWithContext(err, map[string]interface{}{
			"operation": "connection_check",
			"url":       c.baseURL,
		})
	}

	c.mu.Lock()
	c.isHealthy = true
	c.connectionTested = true
	c.mu.Unlock()

	c.config.Logger.Info("MCF connection established", slog.String("url", c.baseURL))
	return nil
}

// IsSerenaConnected checks Serena component accessibility with error handling
func (c *Client) IsSerenaConnected(ctx context.Context) bool {
	status, err := c.GetStatus(ctx)
	if err != nil {
		c.config.Logger.Warn("Failed to check Serena connection", slog.String("error", err.Error()))
		return false
	}
	return status.Connected
}

// IsHealthy returns the current health status of the client
func (c *Client) IsHealthy() bool {
	c.mu.RLock()
	defer c.mu.RUnlock()
	return c.isHealthy
}

// GetErrorStats returns error statistics from the error handler
func (c *Client) GetErrorStats() map[errors.ErrorType]int {
	return c.errorHandler.GetStats()
}

// GetRecentErrors returns recent errors
func (c *Client) GetRecentErrors() []*errors.AppError {
	return c.errorHandler.GetRecentErrors()
}

// LoadConfig loads configuration with validation (backward compatibility method)
func (c *Client) LoadConfig() (string, error) {
	// This is a placeholder for backward compatibility
	// In a real implementation, this would load and validate configuration
	ctx := context.Background()
	status, err := c.GetStatus(ctx)
	if err != nil {
		return "", err
	}

	return fmt.Sprintf("Config version: %s", status.ConfigVersion), nil
}

// Refresh triggers a data refresh (backward compatibility method)
func (c *Client) Refresh() error {
	ctx := context.Background()
	return c.CheckConnection(ctx)
}

// Search performs a search operation (backward compatibility method)
func (c *Client) Search(term string) ([]string, error) {
	// Validate search term
	if strings.TrimSpace(term) == "" {
		return nil, errors.NewValidationError("empty search term", "Search term cannot be empty")
	}

	// This is a placeholder implementation
	return []string{fmt.Sprintf("Search results for: %s", term)}, nil
}

// Clone creates a thread-safe copy of the client
func (c *Client) Clone() *Client {
	c.mu.RLock()
	defer c.mu.RUnlock()

	return &Client{
		baseURL:      c.baseURL,
		httpClient:   c.httpClient,
		config:       c.config,
		lastStatus:   c.lastStatus,
		lastChecksum: c.lastChecksum,
		errorHandler: c.errorHandler,
		validator:    c.validator,
		isHealthy:    c.isHealthy,
	}
}

// validateStatusResponse validates the status response data
func (c *Client) validateStatusResponse(status *Status) error {
	if status.Version == "" {
		return errors.NewValidationError("invalid status response", "version field is missing")
	}

	if status.Uptime == "" {
		return errors.NewValidationError("invalid status response", "uptime field is missing")
	}

	return nil
}

// isRetryableError determines if an error should be retried
func (c *Client) isRetryableError(err error) bool {
	if err == nil {
		return false
	}

	// Check if it's our custom error type
	if appErr, ok := err.(*errors.AppError); ok {
		return appErr.IsRetryable()
	}

	// Check for common retryable error patterns
	if errors.IsRetryableError(err) {
		return true
	}

	// Additional checks for network errors
	if isTimeoutError(err) || isConnectionError(err) {
		return true
	}

	return false
}

// isTimeoutError checks if the error is a timeout
func isTimeoutError(err error) bool {
	if err == nil {
		return false
	}

	// Check for timeout in error message
	errStr := err.Error()
	return strings.Contains(errStr, "timeout") ||
		   strings.Contains(errStr, "deadline exceeded") ||
		   strings.Contains(errStr, "context canceled")
}

// isConnectionError checks if the error is a connection error
func isConnectionError(err error) bool {
	if err == nil {
		return false
	}

	errStr := err.Error()
	return strings.Contains(errStr, "connection refused") ||
		   strings.Contains(errStr, "no such host") ||
		   strings.Contains(errStr, "network is unreachable")
}

