package ui

import (
	"fmt"
	"strings"
	"time"

	"github.com/charmbracelet/lipgloss"
	"mcf-tui/internal/errors"
)

// ErrorNotification represents an error notification component
type ErrorNotification struct {
	width      int
	height     int
	errors     []*NotificationError
	maxErrors  int
	autoHide   bool
	hideDelay  time.Duration
	visible    bool
}

// NotificationError wraps an error for notification display
type NotificationError struct {
	Error     *errors.AppError
	Timestamp time.Time
	Dismissed bool
	AutoHide  bool
}

// NewErrorNotification creates a new error notification component
func NewErrorNotification() *ErrorNotification {
	return &ErrorNotification{
		errors:    make([]*NotificationError, 0),
		maxErrors: 10,
		autoHide:  true,
		hideDelay: 5 * time.Second,
		visible:   false,
	}
}

// SetSize updates the notification dimensions
func (e *ErrorNotification) SetSize(width, height int) {
	e.width = width
	e.height = height
}

// AddError adds a new error to the notification system
func (e *ErrorNotification) AddError(err *errors.AppError) {
	notification := &NotificationError{
		Error:     err,
		Timestamp: time.Now(),
		Dismissed: false,
		AutoHide:  e.shouldAutoHide(err),
	}

	e.errors = append(e.errors, notification)
	e.visible = true

	// Remove old errors if we exceed the maximum
	if len(e.errors) > e.maxErrors {
		e.errors = e.errors[1:]
	}

	// Set up auto-hide for non-critical errors
	if notification.AutoHide && e.autoHide {
		go func() {
			time.Sleep(e.hideDelay)
			notification.Dismissed = true
			e.checkVisibility()
		}()
	}
}

// DismissAll dismisses all current error notifications
func (e *ErrorNotification) DismissAll() {
	for _, err := range e.errors {
		err.Dismissed = true
	}
	e.visible = false
}

// DismissError dismisses a specific error by index
func (e *ErrorNotification) DismissError(index int) {
	if index >= 0 && index < len(e.errors) {
		e.errors[index].Dismissed = true
		e.checkVisibility()
	}
}

// IsVisible returns whether there are visible notifications
func (e *ErrorNotification) IsVisible() bool {
	return e.visible && len(e.getVisibleErrors()) > 0
}

// GetErrorCount returns the number of visible errors
func (e *ErrorNotification) GetErrorCount() int {
	return len(e.getVisibleErrors())
}

// Render renders the error notification component
func (e *ErrorNotification) Render() string {
	if !e.IsVisible() {
		return ""
	}

	visibleErrors := e.getVisibleErrors()
	if len(visibleErrors) == 0 {
		return ""
	}

	var notifications []string

	for i, notificationErr := range visibleErrors {
		notification := e.renderErrorNotification(notificationErr, i)
		notifications = append(notifications, notification)
	}

	// Join all notifications
	content := strings.Join(notifications, "\n")

	// Create container with appropriate styling
	containerStyle := lipgloss.NewStyle().
		Width(e.width - 4).
		MaxHeight(e.height/3).
		Border(lipgloss.RoundedBorder()).
		BorderForeground(Colors.Error).
		Padding(1).
		Margin(1)

	return containerStyle.Render(content)
}

// renderErrorNotification renders a single error notification
func (e *ErrorNotification) renderErrorNotification(notificationErr *NotificationError, index int) string {
	err := notificationErr.Error

	// Choose color based on severity
	var borderColor, textColor lipgloss.Color
	var icon string

	switch err.Severity {
	case errors.SeverityInfo:
		borderColor = Colors.Primary
		textColor = Colors.Primary
		icon = "ℹ"
	case errors.SeverityWarning:
		borderColor = lipgloss.Color("3") // Yellow
		textColor = lipgloss.Color("3")
		icon = "⚠"
	case errors.SeverityError:
		borderColor = Colors.Error
		textColor = Colors.Error
		icon = "✗"
	case errors.SeverityCritical:
		borderColor = lipgloss.Color("9") // Bright red
		textColor = lipgloss.Color("9")
		icon = "💥"
	}

	// Header with icon and timestamp
	timeStr := notificationErr.Timestamp.Format("15:04:05")
	header := lipgloss.NewStyle().
		Foreground(textColor).
		Bold(true).
		Render(fmt.Sprintf("%s %s", icon, timeStr))

	// User message or error message
	message := err.GetUserMessage()
	if message == "" {
		message = err.Message
	}

	messageStyle := lipgloss.NewStyle().
		Foreground(textColor).
		Width(e.width - 12)

	// Add error details if available and not too long
	details := ""
	if err.Details != "" && len(err.Details) < 100 {
