			Italic(true).
			Render("Details: " + err.Details)
	}

	// Recovery suggestion for retryable errors
	suggestion := ""
	if err.Retryable {
		suggestion = lipgloss.NewStyle().
			Foreground(Colors.Accent).
			Render("💡 Tip: This error may be temporary. Try the operation again.")
	}

	// Compose the notification content
	var content []string
	content = append(content, header)
	content = append(content, messageStyle.Render(message))

	if details != "" {
		content = append(content, details)
	}

	if suggestion != "" {
		content = append(content, suggestion)
	}

	// Dismissal hint for critical errors
	if err.Severity == errors.SeverityCritical {
		dismissHint := lipgloss.NewStyle().
			Foreground(Colors.Muted).
			Render("Press 'Ctrl+D' to dismiss")
		content = append(content, dismissHint)
	}

	notificationContent := strings.Join(content, "\n")

	// Style the notification container
	notificationStyle := lipgloss.NewStyle().
		Border(lipgloss.NormalBorder()).
		BorderForeground(borderColor).
		Padding(0, 1).
		Margin(0, 0, 1, 0).
		Width(e.width - 8)

	return notificationStyle.Render(notificationContent)
}

// shouldAutoHide determines if an error should auto-hide
func (e *ErrorNotification) shouldAutoHide(err *errors.AppError) bool {
	// Critical errors should not auto-hide
	if err.Severity == errors.SeverityCritical {
		return false
	}

	// Network errors that are retryable should auto-hide
	if err.Type == errors.ErrorTypeNetwork && err.Retryable {
		return true
	}

	// Info and warning messages should auto-hide
	if err.Severity == errors.SeverityInfo || err.Severity == errors.SeverityWarning {
		return true
	}

	// Validation errors should not auto-hide (user needs to fix them)
	if err.Type == errors.ErrorTypeValidation {
		return false
	}

	return true
}

// getVisibleErrors returns errors that should be displayed
func (e *ErrorNotification) getVisibleErrors() []*NotificationError {
	var visible []*NotificationError
	for _, err := range e.errors {
		if !err.Dismissed {
			visible = append(visible, err)
		}
	}
	return visible
}

// checkVisibility updates the visible state based on remaining errors
func (e *ErrorNotification) checkVisibility() {
	e.visible = len(e.getVisibleErrors()) > 0
}

// GetRecentErrors returns the most recent errors for logging/debugging
func (e *ErrorNotification) GetRecentErrors() []*NotificationError {
	return e.errors
}

// ClearOldErrors removes errors older than the specified duration
func (e *ErrorNotification) ClearOldErrors(maxAge time.Duration) {
	now := time.Now()
	var recentErrors []*NotificationError

	for _, err := range e.errors {
		if now.Sub(err.Timestamp) < maxAge {
			recentErrors = append(recentErrors, err)
		}
	}

	e.errors = recentErrors
	e.checkVisibility()
}

// GetErrorSummary returns a summary of error counts by type
