	RetryDelay  int    `yaml:"retry_delay_seconds"` // Delay between retries in seconds
}

// UIConfig represents UI-specific configuration
type UIConfig struct {
	ShowStatusBar    bool `yaml:"show_status_bar"`
	ShowLineNumbers  bool `yaml:"show_line_numbers"`
	CompactMode      bool `yaml:"compact_mode"`
	AnimationEnabled bool `yaml:"animation_enabled"`
	ErrorAutoHide    bool `yaml:"error_auto_hide"`
	ErrorHideDelay   int  `yaml:"error_hide_delay_seconds"`
}

// ErrorHandlingConfig represents error handling configuration
type ErrorHandlingConfig struct {
	LogErrors        bool `yaml:"log_errors"`
	ShowStackTrace   bool `yaml:"show_stack_trace"`
	RetryOnFailure   bool `yaml:"retry_on_failure"`
	MaxErrorHistory  int  `yaml:"max_error_history"`
	DetailedLogging  bool `yaml:"detailed_logging"`
	NotifyOnError    bool `yaml:"notify_on_error"`
	CriticalErrorLog string `yaml:"critical_error_log_file"`
}

// ConfigManager manages configuration loading and validation
type ConfigManager struct {
	validator    *validation.ConfigValidator
	errorHandler *errors.ErrorHandler
}

// NewConfigManager creates a new configuration manager
func NewConfigManager(errorHandler *errors.ErrorHandler) *ConfigManager {
	return &ConfigManager{
		validator:    validation.NewConfigValidator(),
		errorHandler: errorHandler,
	}
}

// DefaultConfig returns the default configuration with enhanced error handling
func DefaultConfig() *Config {
	homeDir, _ := os.UserHomeDir()

	return &Config{
		LogLevel:    "info",
		Theme:       "default",
		RefreshRate: 1000, // milliseconds

		MCF: MCFConfig{
			ConfigPath:  filepath.Join(homeDir, ".mcf", "config.yaml"),
			LogPath:     filepath.Join(homeDir, ".mcf", "logs"),
			SerenaURL:   "http://localhost:24282",
			MaxLogLines: 100,
			Timeout:     10, // seconds
			MaxRetries:  3,
			RetryDelay:  1, // seconds
		},

		UI: UIConfig{
			ShowStatusBar:    true,
			ShowLineNumbers:  false,
			CompactMode:      false,
			AnimationEnabled: true,
			ErrorAutoHide:    true,
			ErrorHideDelay:   5, // seconds
		},

		ErrorHandling: ErrorHandlingConfig{
			LogErrors:        true,
			ShowStackTrace:   false,
			RetryOnFailure:   true,
			MaxErrorHistory:  50,
			DetailedLogging:  false,
			NotifyOnError:    true,
			CriticalErrorLog: filepath.Join(homeDir, ".mcf", "critical_errors.log"),
		},
	}
}

// Load loads configuration from file with comprehensive validation and error handling
func Load() (*Config, error) {
	return LoadWithManager(nil)
}

// LoadWithManager loads configuration with a specific config manager
func LoadWithManager(manager *ConfigManager) (*Config, error) {
	if manager == nil {
		manager = NewConfigManager(nil)
	}

	// Start with default configuration
	config := DefaultConfig()

	// Get configuration file path
	configPath, err := GetConfigPath()
	if err != nil {
		return nil, manager.handleError(errors.NewConfigurationError(
			"failed to determine config path", 
			err.Error(),
		))
	}

	// Check if config file exists
	if _, err := os.Stat(configPath); os.IsNotExist(err) {
		// Config file doesn't exist, create it with defaults
		if err := manager.createDefaultConfigFile(configPath, config); err != nil {
			// Log warning but continue with default config
			if manager.errorHandler != nil {
				manager.errorHandler.Handle(errors.NewConfigurationError(
					"failed to create default config file",
					err.Error(),
				))
			}
		}
		return config, nil
	}

	// TODO: Implement YAML config file loading and merging with defaults
	// For now, we'll validate the default configuration
	if err := manager.validateConfig(config); err != nil {
		return nil, manager.handleError(err)
	}

	return config, nil
}

// ValidateConfig validates configuration values
func (cm *ConfigManager) ValidateConfig(config *Config) error {
	return cm.validateConfig(config)
}

// validateConfig performs comprehensive configuration validation
func (cm *ConfigManager) validateConfig(config *Config) error {
	// Create validation data map
	validationData := map[string]interface{}{
		"log_level":           config.LogLevel,
		"theme":              config.Theme,
		"refresh_rate":       config.RefreshRate,
		"serena_url":         config.MCF.SerenaURL,
		"max_log_lines":      config.MCF.MaxLogLines,
		"timeout_seconds":    config.MCF.Timeout,
		"max_retries":        config.MCF.MaxRetries,
		"retry_delay":        config.MCF.RetryDelay,
		"max_error_history":  config.ErrorHandling.MaxErrorHistory,
	}

	// Perform validation
	if err := cm.validator.ValidateConfig(validationData); err != nil {
		return err
	}

	// Additional business logic validation
	if err := cm.validateBusinessRules(config); err != nil {
		return err
	}

	return nil
}

// validateBusinessRules validates business logic constraints
func (cm *ConfigManager) validateBusinessRules(config *Config) error {
	// Validate paths exist or can be created
	if err := cm.validatePaths(config); err != nil {
		return err
	}

	// Validate network configuration
	if err := cm.validateNetworkConfig(config); err != nil {
		return err
	}

	// Validate error handling configuration
	if err := cm.validateErrorHandlingConfig(config); err != nil {
		return err
	}

	return nil
}

// validatePaths validates that required paths exist or can be created
func (cm *ConfigManager) validatePaths(config *Config) error {
	paths := []struct {
		path string
		name string
	}{
		{config.MCF.ConfigPath, "MCF config path"},
		{config.MCF.LogPath, "MCF log path"},
		{config.ErrorHandling.CriticalErrorLog, "critical error log path"},
	}

	for _, p := range paths {
		dir := filepath.Dir(p.path)
		if err := os.MkdirAll(dir, 0755); err != nil {
			return errors.NewConfigurationError(
				fmt.Sprintf("cannot create directory for %s", p.name),
				fmt.Sprintf("Path: %s, Error: %s", dir, err.Error()),
			)
		}
	}

	return nil
}

// validateNetworkConfig validates network-related configuration
func (cm *ConfigManager) validateNetworkConfig(config *Config) error {
	// Validate timeout values
	if config.MCF.Timeout <= 0 || config.MCF.Timeout > 300 {
		return errors.NewConfigurationError(
			"invalid timeout configuration",
			"Timeout must be between 1 and 300 seconds",
		)
	}

	// Validate retry configuration
	if config.MCF.MaxRetries < 0 || config.MCF.MaxRetries > 10 {
		return errors.NewConfigurationError(
			"invalid retry configuration",
			"Max retries must be between 0 and 10",
		)
	}

	if config.MCF.RetryDelay <= 0 || config.MCF.RetryDelay > 60 {
		return errors.NewConfigurationError(
			"invalid retry delay configuration",
			"Retry delay must be between 1 and 60 seconds",
		)
	}

	return nil
}

// validateErrorHandlingConfig validates error handling configuration
func (cm *ConfigManager) validateErrorHandlingConfig(config *Config) error {
	// Validate error history limits
	if config.ErrorHandling.MaxErrorHistory <= 0 || config.ErrorHandling.MaxErrorHistory > 1000 {
		return errors.NewConfigurationError(
			"invalid error history configuration",
			"Max error history must be between 1 and 1000",
		)
	}

	// Validate error hide delay
	if config.UI.ErrorHideDelay <= 0 || config.UI.ErrorHideDelay > 300 {
		return errors.NewConfigurationError(
			"invalid error hide delay configuration",
			"Error hide delay must be between 1 and 300 seconds",
		)
	}

	return nil
}

// createDefaultConfigFile creates a default configuration file
func (cm *ConfigManager) createDefaultConfigFile(path string, config *Config) error {
	// Create directory if it doesn't exist
	dir := filepath.Dir(path)
	if err := os.MkdirAll(dir, 0755); err != nil {
		return fmt.Errorf("failed to create config directory: %w", err)
	}

	// TODO: Implement YAML marshaling and file creation
	// For now, just create an empty file to indicate the config directory exists
	file, err := os.Create(path + ".placeholder")
	if err != nil {
		return fmt.Errorf("failed to create config placeholder: %w", err)
	}
	defer file.Close()

	// Write a comment indicating this is a placeholder
	_, err = file.WriteString("# MCF TUI Configuration placeholder\n# TODO: Implement full YAML configuration\n")
	return err
}

// handleError processes configuration errors through the error handler
func (cm *ConfigManager) handleError(err error) error {
	if cm.errorHandler != nil {
		return cm.errorHandler.Handle(err)
	}
	return err
}

// GetConfigPath returns the path to the configuration file with enhanced error handling
func GetConfigPath() (string, error) {
	homeDir, err := os.UserHomeDir()
	if err != nil {
		return "", errors.NewConfigurationError(
			"cannot determine home directory",
			err.Error(),
		)
	}

	configDir := filepath.Join(homeDir, ".mcf")

	// Ensure config directory exists
	if err := os.MkdirAll(configDir, 0755); err != nil {
		return "", errors.NewConfigurationError(
			"cannot create config directory",
			fmt.Sprintf("Directory: %s, Error: %s", configDir, err.Error()),
		)
	}

	return filepath.Join(configDir, "tui-config.yaml"), nil
}

// Reload reloads the configuration from disk
func (cm *ConfigManager) Reload() (*Config, error) {
	return LoadWithManager(cm)
}

// IsValid checks if a configuration is valid
func (cm *ConfigManager) IsValid(config *Config) bool {
	return cm.validateConfig(config) == nil
}

// GetValidationErrors returns all validation errors for a configuration
func (cm *ConfigManager) GetValidationErrors(config *Config) []string {
	err := cm.validateConfig(config)
	if err == nil {
		return nil
	}

	// Extract error messages
	if appErr, ok := err.(*errors.AppError); ok {
		return []string{appErr.GetUserMessage()}
	}

	return []string{err.Error()}
}

