package app

import (
	"context"
	"log/slog"
	"time"

	"github.com/charmbracelet/bubbles/key"
	tea "github.com/charmbracelet/bubbletea"
	"github.com/charmbracelet/lipgloss"

	"mcf-tui/internal/config"
	"mcf-tui/internal/errors"
	"mcf-tui/internal/mcf"
	"mcf-tui/internal/ui"
	"mcf-tui/internal/validation"
)

// ViewState represents the current active view
type ViewState int

const (
	ViewDashboard ViewState = iota
	ViewLogs
	ViewHelp
)

// Model represents the root application state with comprehensive error handling
type Model struct {
	// Current view state
	currentView ViewState

	// UI dimensions
	width  int
	height int

	// Application state
	ready       bool
	quitting    bool
	initialized bool

	// Last update time for performance tracking
	lastUpdate time.Time

	// Key bindings
	keys KeyMap

	// UI components
	navigation        *ui.Navigation
	dashboard         *ui.Dashboard
	logsViewer        *ui.LogsViewer
	helpViewer        *ui.HelpViewer
	commandBar        *ui.CommandBar
	errorNotification *ui.ErrorNotification

	// MCF client with enhanced error handling
	mcfClient *mcf.Client

	// Error handling system
	errorHandler *errors.ErrorHandler

	// Configuration management
	config        *config.Config
	configManager *config.ConfigManager

	// Validation
	commandValidator *validation.CommandValidator

	// Application context for cancellation
	ctx    context.Context
	cancel context.CancelFunc

	// Logger
	logger *slog.Logger
}

// KeyMap defines the key bindings for the application
type KeyMap struct {
	Tab        key.Binding
	Quit       key.Binding
	Help       key.Binding
	Enter      key.Binding
	Command    key.Binding
	DismissErr key.Binding // New key binding for dismissing errors
}

// DefaultKeyMap returns the default key bindings
func DefaultKeyMap() KeyMap {
	return KeyMap{
		Tab: key.NewBinding(
			key.WithKeys("tab"),
			key.WithHelp("tab", "switch view"),
		),
		Quit: key.NewBinding(
			key.WithKeys("q", "esc", "ctrl+c"),
			key.WithHelp("q", "quit"),
		),
		Help: key.NewBinding(
			key.WithKeys("?"),
			key.WithHelp("?", "help"),
		),
		Enter: key.NewBinding(
			key.WithKeys("enter"),
			key.WithHelp("enter", "execute"),
		),
		Command: key.NewBinding(
			key.WithKeys(":"),
			key.WithHelp(":", "command mode"),
		),
		DismissErr: key.NewBinding(
			key.WithKeys("ctrl+d"),
			key.WithHelp("ctrl+d", "dismiss errors"),
		),
	}
}

// NewModel creates a new application model with comprehensive error handling
func NewModel() Model {
	// Set up application context
	ctx, cancel := context.WithCancel(context.Background())

	// Initialize logger
	logger := slog.Default()

	// Create error handler
	errorHandler := errors.NewErrorHandler(logger)

	// Initialize configuration manager
	configManager := config.NewConfigManager(errorHandler)

	// Load configuration
	cfg, err := configManager.Reload()
	if err != nil {
		// If config loading fails, use defaults but log the error
		cfg = config.DefaultConfig()
		errorHandler.Handle(err)
	}

	// Create MCF client with error handling
	mcfClient := mcf.NewClientWithConfig(mcf.ClientConfig{
		BaseURL:       cfg.MCF.SerenaURL,
		Timeout:       time.Duration(cfg.MCF.Timeout) * time.Second,
		RetryAttempts: cfg.MCF.MaxRetries,
		RetryDelay:    time.Duration(cfg.MCF.RetryDelay) * time.Second,
		Logger:        logger,
	})

	// Create error notification component
	errorNotification := ui.NewErrorNotification()

	// Subscribe error notification to error handler
	errorHandler.Subscribe(&errorNotificationSubscriber{
		notification: errorNotification,
		config:       cfg,
	})

	model := Model{
		currentView:       ViewDashboard,
		ready:            false,
		quitting:         false,
		initialized:      false,
		lastUpdate:       time.Now(),
		keys:             DefaultKeyMap(),
		navigation:       ui.NewNavigation(),
		dashboard:        ui.NewDashboard(),
		logsViewer:       ui.NewLogsViewer(),
		helpViewer:       ui.NewHelpViewer(),
		commandBar:       ui.NewCommandBar(),
		errorNotification: errorNotification,
		mcfClient:        mcfClient,
		errorHandler:     errorHandler,
		config:           cfg,
		configManager:    configManager,
		commandValidator: validation.NewCommandValidator(),
		ctx:              ctx,
		cancel:           cancel,
		logger:           logger,
	}

	return model
}

// Init initializes the application with proper error handling
func (m Model) Init() tea.Cmd {
	// Perform initial setup with error handling
	return tea.Batch(
		m.initializeComponents(),
		m.checkMCFConnection(),
	)
}

// initializeComponents initializes application components
func (m Model) initializeComponents() tea.Cmd {
	return func() tea.Msg {
		defer m.errorHandler.Recover()

		// Log application startup
		m.logger.Info("Initializing MCF TUI application")

		// Validate configuration
		if !m.configManager.IsValid(m.config) {
			validationErrors := m.configManager.GetValidationErrors(m.config)
			for _, errMsg := range validationErrors {
				m.errorHandler.Handle(errors.NewConfigurationError("configuration validation failed", errMsg))
			}
		}

		return initCompleteMsg{}
	}
}

// checkMCFConnection checks the initial MCF connection
func (m Model) checkMCFConnection() tea.Cmd {
	return func() tea.Msg {
		defer m.errorHandler.Recover()

		// Check MCF connection with timeout
		ctx, cancel := context.WithTimeout(m.ctx, 5*time.Second)
		defer cancel()

		if err := m.mcfClient.CheckConnection(ctx); err != nil {
			// Connection failed - this is handled by the error handler in the client
			return connectionFailedMsg{err: err}
		}

		m.logger.Info("MCF connection established successfully")
		return connectionSuccessMsg{}
	}
}

// View renders the application with error notifications
func (m Model) View() string {
	if !m.ready {
		return m.renderLoadingScreen()
	}

	// Update component sizes
	m.updateComponentSizes()

	// Render navigation
	navBar := m.navigation.Render()

	// Render current view content
	content := m.renderCurrentView()

	// Render command bar
	commandBar := m.commandBar.Render()

	// Render error notifications if visible
	errorNotifications := ""
	if m.errorNotification.IsVisible() {
		errorNotifications = m.errorNotification.Render()
	}

	// Combine all elements
	var sections []string
	sections = append(sections, navBar)

	if errorNotifications != "" {
		sections = append(sections, errorNotifications)
	}

	sections = append(sections, content, commandBar)

	return lipgloss.JoinVertical(lipgloss.Left, sections...)
}

// renderLoadingScreen renders the loading screen with error information
func (m Model) renderLoadingScreen() string {
	loadingText := "Loading MCF TUI..."

	if m.errorNotification.GetErrorCount() > 0 {
		errorText := lipgloss.NewStyle().
			Foreground(ui.Colors.Error).
			Render("Initialization errors detected")

		return lipgloss.JoinVertical(
			lipgloss.Left,
			loadingText,
			errorText,
			m.errorNotification.Render(),
		)
	}

	return loadingText
}

// updateComponentSizes updates component dimensions
func (m *Model) updateComponentSizes() {
	// Calculate available space considering error notifications
	availableHeight := m.height - 5 // Navigation + command bar

	if m.errorNotification.IsVisible() {
		// Reserve space for error notifications
		errorHeight := m.height / 3
		if errorHeight > 10 {
			errorHeight = 10
		}
		availableHeight -= errorHeight
		m.errorNotification.SetSize(m.width, errorHeight)
	}

	// Update component sizes
	m.navigation.SetWidth(m.width)
	m.dashboard.SetSize(m.width, availableHeight)
	m.logsViewer.SetSize(m.width, availableHeight)
	m.helpViewer.SetSize(m.width, availableHeight)
	m.commandBar.SetWidth(m.width)
}

// renderCurrentView renders the content for the current view
func (m Model) renderCurrentView() string {
	switch m.currentView {
	case ViewDashboard:
		return m.dashboard.Render()
	case ViewLogs:
		return m.logsViewer.Render()
	case ViewHelp:
		return m.helpViewer.Render()
	default:
		// This should never happen, but handle it gracefully
		m.errorHandler.Handle(errors.NewValidationError("unknown view state", 
			"Invalid view state encountered"))
		return "Unknown view - please restart the application"
	}
}

// Custom message types for error handling
type initCompleteMsg struct{}
type connectionSuccessMsg struct{}
type connectionFailedMsg struct{ err error }

// errorNotificationSubscriber implements ErrorSubscriber for UI notifications
type errorNotificationSubscriber struct {
	notification *ui.ErrorNotification
	config       *config.Config
}

// OnError handles error notifications
func (s *errorNotificationSubscriber) OnError(err *errors.AppError) {
	// Only add to notifications if configured to do so
	if s.config.ErrorHandling.NotifyOnError {
		s.notification.AddError(err)
	}
}

