		m.logsViewer.searchInput, cmd = m.logsViewer.searchInput.Update(msg)

		switch msg.Type {
		case tea.KeyEnter:
			// Perform search
			m.logsViewer.performSearch(m.logsViewer.searchInput.Value())
			m.logsViewer.searchInput.Blur()
		case tea.KeyEsc:
			// Cancel search
			m.logsViewer.searchInput.Blur()
			m.logsViewer.searchQuery = ""
		}
		return m, cmd
	}

	switch msg.String() {
	case "up", "k":
		m.logsViewer.ScrollUp()
		return m, nil
	case "down", "j":
		m.logsViewer.ScrollDown()
		return m, nil
	case "pgup":
		m.logsViewer.PageUp()
		return m, nil
	case "pgdown":
		m.logsViewer.PageDown()
		return m, nil
	case "home":
		m.logsViewer.ScrollToTop()
		return m, nil
	case "end":
		m.logsViewer.ScrollToBottom()
		return m, nil
	case "/":
