		// Trigger data refresh
		err := m.mcfClient.Refresh()
		if err != nil {
			m.logsViewer.AddLog("[ERROR] Refresh failed: " + err.Error())
		} else {
			m.logsViewer.AddLog("[INFO] Data refreshed successfully")
		}

	case ":export":
		// Export current dashboard data
		exportPath, err := m.dashboard.ExportData()
		if err != nil {
			m.logsViewer.AddLog("[ERROR] Export failed: " + err.Error())
		} else {
			m.logsViewer.AddLog("[INFO] Data exported to: " + exportPath)
		}

	default:
		// Advanced command parsing with argument support
		parts := strings.Split(command, " ")
		switch parts[0] {
		case ":search":
			if len(parts) > 1 {
				searchResults, err := m.mcfClient.Search(parts[1])
				if err != nil {
					m.logsViewer.AddLog("[ERROR] Search failed: " + err.Error())
				} else {
					m.logsViewer.AddLog("[INFO] Search results: " + strings.Join(searchResults, ", "))
				}
			} else {
				m.logsViewer.AddLog("[ERROR] :search requires a search term")
			}

		default:
			m.logsViewer.AddLog("[ERROR] Unknown command: " + command)
		}
	}

	return m, nil
}

