package ui

import (
	"fmt"
	"strings"

	"github.com/charmbracelet/bubbles/textinput"
	"github.com/charmbracelet/lipgloss"
)

// LogsViewer represents the logs viewer component
type LogsViewer struct {
	width  int
	height int
	logs   []string
	scroll int

	// Navigation and search features
	selectedLine       int
	searchInput        textinput.Model
	searchQuery        string
	searchResult       []int
	currentSearchIndex int
}

// NewLogsViewer creates a new logs viewer component
func NewLogsViewer() *LogsViewer {
	// Initialize search input
	si := textinput.New()
	si.Placeholder = "Search logs..."
	si.Width = 30

	return &LogsViewer{
		logs: []string{
			"[2025-08-31 14:30:15] [INFO] MCF TUI started successfully",
			"[2025-08-31 14:30:15] [INFO] Serena connection established",
			"[2025-08-31 14:30:15] [INFO] Configuration loaded from ~/.mcf/config.yaml",
			"[2025-08-31 14:30:16] [DEBUG] Dashboard view initialized",
			"[2025-08-31 14:30:16] [INFO] Ready for user input",
			"[2025-08-31 14:30:20] [DEBUG] User switched to logs view",
			"[2025-08-31 14:30:25] [INFO] MCF client connection verified",
			"[2025-08-31 14:30:30] [DEBUG] UI refresh cycle completed",
		},
		scroll:       0,
		selectedLine: -1,
		searchInput:  si,
	}
}

// SetSize updates the logs viewer dimensions
func (l *LogsViewer) SetSize(width, height int) {
	l.width = width
	l.height = height
}

// AddLog adds a new log entry
func (l *LogsViewer) AddLog(logEntry string) {
	l.logs = append(l.logs, logEntry)

	// Auto-scroll to bottom for new entries
	maxVisible := l.height - 6 // Account for borders and headers
	if len(l.logs) > maxVisible {
		l.scroll = len(l.logs) - maxVisible
	}

	// Update search results if search is active
	if l.searchQuery != "" {
		l.performSearch(l.searchQuery)
	}
}

// ScrollUp scrolls the log view up
func (l *LogsViewer) ScrollUp() {
	if l.scroll > 0 {
		l.scroll--
	}
	l.adjustSelectedLine()
}

// ScrollDown scrolls the log view down
func (l *LogsViewer) ScrollDown() {
	maxScroll := len(l.logs) - (l.height - 6)
	if maxScroll < 0 {
		maxScroll = 0
	}
	if l.scroll < maxScroll {
		l.scroll++
	}
	l.adjustSelectedLine()
}

// PageUp scrolls up a full page
func (l *LogsViewer) PageUp() {
	pageSize := l.height - 6
	l.scroll -= pageSize
	if l.scroll < 0 {
		l.scroll = 0
	}
	l.adjustSelectedLine()
}

// PageDown scrolls down a full page
func (l *LogsViewer) PageDown() {
	pageSize := l.height - 6
	maxScroll := len(l.logs) - pageSize
	l.scroll += pageSize
	if l.scroll > maxScroll {
		l.scroll = maxScroll
	}
	l.adjustSelectedLine()
}

// ScrollToTop moves to the top of the logs
func (l *LogsViewer) ScrollToTop() {
	l.scroll = 0
	l.selectedLine = 0
}

// ScrollToBottom moves to the bottom of the logs
func (l *LogsViewer) ScrollToBottom() {
	l.scroll = len(l.logs) - (l.height - 6)
	if l.scroll < 0 {
		l.scroll = 0
	}
	l.selectedLine = len(l.logs) - 1
}

// adjustSelectedLine ensures the selected line stays within view after scrolling
func (l *LogsViewer) adjustSelectedLine() {
	viewStart := l.scroll
	viewEnd := l.scroll + (l.height - 6)

	if l.selectedLine < viewStart {
		l.selectedLine = viewStart
	}
	if l.selectedLine >= viewEnd {
		l.selectedLine = viewEnd - 1
	}
}

// SelectLineRelative selects a line relative to the current selection
func (l *LogsViewer) SelectLineRelative(offset int) {
	newSelection := l.selectedLine + offset

	// Bounds checking
	if newSelection >= 0 && newSelection < len(l.logs) {
		l.selectedLine = newSelection

		// Adjust scroll if needed
		viewStart := l.scroll
		viewEnd := l.scroll + (l.height - 6)

		if l.selectedLine < viewStart {
			l.scroll = l.selectedLine
		}
		if l.selectedLine >= viewEnd {
			l.scroll = l.selectedLine - (l.height - 6) + 1
		}
	}
}

// performSearch finds all log entries matching the search query
func (l *LogsViewer) performSearch(query string) {
	l.searchQuery = query
	l.searchResult = []int{}

	// Case-insensitive search
	query = strings.ToLower(query)

	for i, log := range l.logs {
		if strings.Contains(strings.ToLower(log), query) {
			l.searchResult = append(l.searchResult, i)
		}
	}

	l.currentSearchIndex = 0
}

// NavigateSearchResults moves to the next or previous search result
func (l *LogsViewer) NavigateSearchResults(forward bool) {
	if len(l.searchResult) == 0 {
		return
	}

	if forward {
		l.currentSearchIndex = (l.currentSearchIndex + 1) % len(l.searchResult)
	} else {
		l.currentSearchIndex = (l.currentSearchIndex - 1 + len(l.searchResult)) % len(l.searchResult)
	}

	// Scroll to the found log entry
	foundIndex := l.searchResult[l.currentSearchIndex]
	l.scroll = foundIndex
	l.selectedLine = foundIndex
}

// ToggleSearch activates or deactivates search mode
func (l *LogsViewer) ToggleSearch() {
	l.searchInput.Reset()
	l.searchInput.Focus()
	l.searchQuery = ""
	l.searchResult = []int{}
}

// Render renders the logs viewer
func (l *LogsViewer) Render() string {
	if l.width <= 0 || l.height <= 0 {
		return "Initializing logs viewer..."
	}

	// Header
	header := Styles.Header.Render("📋 MCF Logs Viewer")

	// Search input rendering
	searchArea := ""
	if l.searchInput.Focused() {
		searchArea = Styles.Body.Render("Search: " + l.searchInput.View())
	}

	// Calculate visible logs
	maxVisible := l.height - 6 // Account for borders and headers
	visibleLogs := l.getVisibleLogs(maxVisible)

	// Format log entries
	var logLines []string
	for i, log := range visibleLogs {
		currentIndex := i + l.scroll
		style := lipgloss.NewStyle()

		// Highlight the selected line
		if currentIndex == l.selectedLine {
			style = style.Background(Colors.Selection)
		}

		// Highlight search results
		if l.searchQuery != "" && strings.Contains(strings.ToLower(log), strings.ToLower(l.searchQuery)) {
			style = style.Foreground(Colors.Highlight)
		}

		// Special highlighting for most recent log
		if currentIndex == len(l.logs)-1 {
			style = style.Foreground(Colors.Success)
		}

		logLines = append(logLines, style.Render(log))
	}

	// Join log lines
	logsContent := strings.Join(logLines, "\n")

	// Create scrollable log area
	logArea := Styles.Body.
		Border(lipgloss.RoundedBorder()).
		BorderForeground(Colors.Secondary).
		Width(l.width - 6).
		Height(maxVisible).
		Render(logsContent)

	// Status bar
	totalLogs := len(l.logs)
	searchInfo := ""
	if l.searchQuery != "" {
		searchInfo = fmt.Sprintf(" | Search: %s (%d/%d)",
			l.searchQuery,
			l.currentSearchIndex+1,
			len(l.searchResult))
	}

	statusText := lipgloss.NewStyle().
		Foreground(Colors.Muted).
		Render(fmt.Sprintf("📊 Total logs: %s | Use ↑/↓ to scroll, / to search%s",
			lipgloss.NewStyle().Foreground(Colors.Accent).Render(fmt.Sprintf("%d", totalLogs)),
			searchInfo))

	// Combine all sections
	content := lipgloss.JoinVertical(
		lipgloss.Left,
		header,
		searchArea,
		"",
		logArea,
		"",
		statusText,
	)

	return ViewBox(content, l.width, l.height)
}

// getVisibleLogs returns the logs that should be visible based on scroll position
func (l *LogsViewer) getVisibleLogs(maxVisible int) []string {
	if len(l.logs) == 0 {
		return []string{"No logs available"}
	}

	start := l.scroll
	end := start + maxVisible

	if end > len(l.logs) {
		end = len(l.logs)
	}

	if start >= len(l.logs) {
		start = len(l.logs) - 1
		if start < 0 {
			start = 0
		}
	}

	return l.logs[start:end]
}

