package ui

import (
	"fmt"
	"strings"
)

// Navigation represents the tab navigation component
type Navigation struct {
	tabs        []Tab
	activeTab   int
	width       int
}

// Tab represents a navigation tab
type Tab struct {
	Label string
	Key   string
	Icon  string
}

// NewNavigation creates a new navigation component
func NewNavigation() *Navigation {
	tabs := []Tab{
		{Label: "Dashboard", Key: "dashboard", Icon: "🚀"},
		{Label: "Logs", Key: "logs", Icon: "📋"},
		{Label: "Help", Key: "help", Icon: "❓"},
	}

	return &Navigation{
		tabs:      tabs,
		activeTab: 0,
	}
}

// SetWidth updates the navigation width
func (n *Navigation) SetWidth(width int) {
	n.width = width
}

// SetActiveTab sets the active tab by index
func (n *Navigation) SetActiveTab(index int) {
	if index >= 0 && index < len(n.tabs) {
		n.activeTab = index
	}
}

// GetActiveTab returns the current active tab index
func (n *Navigation) GetActiveTab() int {
	return n.activeTab
}

// NextTab moves to the next tab
func (n *Navigation) NextTab() {
	n.activeTab = (n.activeTab + 1) % len(n.tabs)
}

// PrevTab moves to the previous tab
func (n *Navigation) PrevTab() {
	n.activeTab = (n.activeTab - 1 + len(n.tabs)) % len(n.tabs)
}

// Render renders the navigation bar
func (n *Navigation) Render() string {
	var renderedTabs []string

	for i, tab := range n.tabs {
		tabContent := fmt.Sprintf("%s %s", tab.Icon, tab.Label)

		if i == n.activeTab {
			// Active tab styling
			renderedTab := Styles.ActiveButton.Render(tabContent)
			renderedTabs = append(renderedTabs, renderedTab)
		} else {
			// Inactive tab styling
			renderedTab := Styles.Button.Render(tabContent)
			renderedTabs = append(renderedTabs, renderedTab)
		}
	}

	// Join tabs with spacing
	tabBar := strings.Join(renderedTabs, "  ")

	// Center the tab bar
	return StatusLine(tabBar, n.width)
}

// GetCurrentTabKey returns the key of the currently active tab
func (n *Navigation) GetCurrentTabKey() string {
	if n.activeTab >= 0 && n.activeTab < len(n.tabs) {
		return n.tabs[n.activeTab].Key
	}
	return ""
}

