// getMCFStatus retrieves MCF status with timeout and error handling
func (m Model) getMCFStatus() tea.Cmd {
	return func() tea.Msg {
		defer m.errorHandler.Recover()

		status, err := m.mcfClient.GetStatus()
		if err != nil {
			return commandErrorMsg{
				command: ":status",
				error:   err,
			}
		}

		return commandSuccessMsg{
			command: ":status",
			result:  "MCF Status: " + status,
		}
	}
}

// loadMCFConfig loads MCF configuration with validation
func (m Model) loadMCFConfig() tea.Cmd {
	return func() tea.Msg {
		defer m.errorHandler.Recover()

		// Reload configuration
		cfg, err := m.configManager.Reload()
		if err != nil {
			return commandErrorMsg{
				command: ":config",
				error:   err,
			}
		}

		// Validate new configuration
		if !m.configManager.IsValid(cfg) {
			validationErrors := m.configManager.GetValidationErrors(cfg)
			errorDetails := strings.Join(validationErrors, "; ")
			return commandErrorMsg{
				command: ":config",
				error:   errors.NewConfigurationError("configuration validation failed", errorDetails),
			}
		}

		return commandSuccessMsg{
			command: ":config",
			result:  "Configuration reloaded successfully",
		}
	}
}

