func (m Model) refreshMCFData() tea.Cmd {
	return func() tea.Msg {
		defer m.errorHandler.Recover()

		ctx, cancel := context.WithTimeout(m.ctx, 15*time.Second)
		defer cancel()

		err := m.mcfClient.Refresh()
		if err != nil {
			return commandErrorMsg{
				command: ":refresh",
