		}
	}
}

// performMCFSearch performs a search with validation
func (m Model) performMCFSearch(term string) tea.Cmd {
	return func() tea.Msg {
		defer m.errorHandler.Recover()

		searchResults, err := m.mcfClient.Search(term)
		if err != nil {
			return commandErrorMsg{
				command: ":search",
				error:   err,
			}
		}

		return commandSuccessMsg{
			command: ":search",
			result:  "Search results: " + strings.Join(searchResults, ", "),
		}
	}
}

// showErrorStatistics displays error statistics
func (m Model) showErrorStatistics() tea.Cmd {
	return func() tea.Msg {
		defer m.errorHandler.Recover()

		stats := m.errorHandler.GetStats()
		recentErrors := m.errorHandler.GetRecentErrors()

		var result strings.Builder
		result.WriteString("Error Statistics:\n")

		for errType, count := range stats {
			result.WriteString("- ")
			result.WriteString(m.errorTypeToString(errType))
			result.WriteString(": ")
			result.WriteString(string(rune(count + '0')))
			result.WriteString("\n")
		}

		result.WriteString("Recent errors: ")
		result.WriteString(string(rune(len(recentErrors) + '0')))

		return commandSuccessMsg{
			command: ":errors",
			result:  result.String(),
		}
	}
}

// retryLastOperation retries the last failed operation
func (m Model) retryLastOperation() tea.Cmd {
	return func() tea.Msg {
		defer m.errorHandler.Recover()

		// Get recent errors to find retryable ones
		recentErrors := m.errorHandler.GetRecentErrors()

		for i := len(recentErrors) - 1; i >= 0; i-- {
			if recentErrors[i].Retryable {
				// For now, just return a success message
				// In a full implementation, we'd store and retry the actual operation
				return commandSuccessMsg{
					command: ":retry",
					result:  "Retry functionality not fully implemented yet",
				}
			}
		}

		return commandErrorMsg{
			command: ":retry",
			error:   errors.NewValidationError("no retryable operations", "No recent retryable operations found"),
		}
	}
}

// errorTypeToString converts error type to string
func (m Model) errorTypeToString(t errors.ErrorType) string {
	switch t {
	case errors.ErrorTypeValidation:
		return "Validation"
	case errors.ErrorTypeNetwork:
		return "Network"
	case errors.ErrorTypeConfiguration:
		return "Configuration"
	case errors.ErrorTypeCommand:
		return "Command"
	case errors.ErrorTypeAuthentication:
		return "Authentication"
	case errors.ErrorTypePermission:
		return "Permission"
	case errors.ErrorTypeTimeout:
		return "Timeout"
	case errors.ErrorTypeSystemResource:
		return "System Resource"
	default:
		return "Unknown"
	}
}

// Custom command message types
type commandSuccessMsg struct {
	command string
	result  string
}

type commandErrorMsg struct {
	command string
	error   error
}

