package app

import (
	"context"
	"strings"
	"time"

	"github.com/charmbracelet/bubbles/key"
	tea "github.com/charmbracelet/bubbletea"

	"mcf-tui/internal/errors"
)

// Update handles all application state updates with comprehensive error handling
func (m Model) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	defer m.errorHandler.Recover()

	switch msg := msg.(type) {

	case tea.WindowSizeMsg:
		m.width = msg.Width
		m.height = msg.Height
		if !m.ready {
			m.ready = true
		}
		return m, nil

	case tea.KeyMsg:
		return m.handleKeyPress(msg)

	case initCompleteMsg:
		m.initialized = true
		m.logger.Info("Application components initialized successfully")
		return m, nil

	case connectionSuccessMsg:
		m.logsViewer.AddLog("[INFO] MCF connection established successfully")
		return m, nil

	case connectionFailedMsg:
		// Handle connection failure
		appErr, ok := msg.err.(*errors.AppError)
		if !ok {
			// Convert generic error to AppError
			appErr = errors.NewNetworkError("MCF connection failed", msg.err, true)
		}

		// Add to error handler (which will notify subscribers)
		m.errorHandler.Handle(appErr)

		// Also add to logs for visibility
		m.logsViewer.AddLog("[ERROR] MCF connection failed: " + appErr.GetUserMessage())
		return m, nil

	case commandSuccessMsg:
		m.logsViewer.AddLog("[INFO] " + msg.result)
		return m, nil

	case commandErrorMsg:
		// Handle command error through error handler
		if appErr, ok := msg.error.(*errors.AppError); ok {
			m.errorHandler.Handle(appErr)
		} else {
			m.errorHandler.Handle(errors.NewCommandError(msg.error.Error(), msg.command))
		}
		return m, nil

	case errorMsg:
		// Legacy error message handling - convert to AppError
		var appErr *errors.AppError
		if ae, ok := msg.error.(*errors.AppError); ok {
			appErr = ae
		} else {
			appErr = &errors.AppError{
				Type:      errors.ErrorTypeUnknown,
				Severity:  errors.SeverityError,
				Code:      "UNKNOWN_ERROR",
				Message:   msg.error.Error(),
				Cause:     msg.error,
				Timestamp: time.Now(),
				UserMsg:   "An unexpected error occurred",
				Retryable: false,
			}
		}

		m.errorHandler.Handle(appErr)
		return m, nil

	default:
		// Update command bar with any message
		m.commandBar.Update(msg)
		return m, nil
	}
}

// errorMsg wraps errors for the tea.Msg interface (legacy support)
type errorMsg struct {
	error error
}

// handleKeyPress processes keyboard input with enhanced error handling
func (m Model) handleKeyPress(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	// Handle error dismissal first
	if key.Matches(msg, m.keys.DismissErr) {
		m.errorNotification.DismissAll()
		return m, nil
	}

	// If command bar is active, handle its input first
	if m.commandBar.IsActive() {
		return m.handleCommandBarInput(msg)
	}

	// Global key bindings
	switch {
	case key.Matches(msg, m.keys.Quit):
		m.quitting = true
		m.cancel() // Cancel any ongoing operations
		return m, tea.Quit

	case key.Matches(msg, m.keys.Command):
		m.commandBar.Activate()
		return m, nil

	case key.Matches(msg, m.keys.Tab):
		m.navigation.NextTab()
		m.currentView = ViewState(m.navigation.GetActiveTab())
		return m, nil

	case key.Matches(msg, m.keys.Help):
		m.navigation.SetActiveTab(2) // Help is index 2
		m.currentView = ViewHelp
		return m, nil
	}

	// View-specific key handling
	switch m.currentView {
	case ViewDashboard:
		return m.handleDashboardKeys(msg)
	case ViewLogs:
		return m.handleLogsKeys(msg)
	case ViewHelp:
		return m.handleHelpKeys(msg)
	}

	return m, nil
}

// handleDashboardKeys handles key presses in dashboard view
func (m Model) handleDashboardKeys(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	// Dashboard-specific key handling
	switch msg.String() {
	case "r":
		// Manual refresh
		return m, m.refreshMCFStatus()
	case "c":
		// Clear error notifications
		m.errorNotification.DismissAll()
		return m, nil
	}
	return m, nil
}

// handleLogsKeys handles key presses in logs view with error handling
func (m Model) handleLogsKeys(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	// Handle search input when focused
	if m.logsViewer.SearchInput.Focused() {
		var cmd tea.Cmd
		m.logsViewer.SearchInput, cmd = m.logsViewer.SearchInput.Update(msg)

		switch msg.Type {
		case tea.KeyEnter:
			// Perform search with validation
			searchTerm := strings.TrimSpace(m.logsViewer.SearchInput.Value())
			if searchTerm == "" {
				m.errorHandler.Handle(errors.NewValidationError("empty search term", "Search term cannot be empty"))
			} else {
				m.logsViewer.PerformSearch(searchTerm)
			}
			m.logsViewer.SearchInput.Blur()
		case tea.KeyEsc:
			// Cancel search
			m.logsViewer.SearchInput.Blur()
			m.logsViewer.SearchQuery = ""
		}
		return m, cmd
	}

	switch msg.String() {
	case "up", "k":
		m.logsViewer.ScrollUp()
		return m, nil
	case "down", "j":
		m.logsViewer.ScrollDown()
		return m, nil
	case "pgup":
		m.logsViewer.PageUp()
		return m, nil
	case "pgdown":
		m.logsViewer.PageDown()
		return m, nil
	case "home":
		m.logsViewer.ScrollToTop()
		return m, nil
	case "end":
		m.logsViewer.ScrollToBottom()
		return m, nil
	case "/":
		// Activate search mode
		m.logsViewer.ToggleSearch()
		return m, nil
	case "n":
		// Next search result
		if m.logsViewer.SearchQuery != "" {
			m.logsViewer.NavigateSearchResults(true)
		}
		return m, nil
	case "N":
		// Previous search result
		if m.logsViewer.SearchQuery != "" {
			m.logsViewer.NavigateSearchResults(false)
		}
		return m, nil
	case "ctrl+j":
		// Scroll down relative to selected line
		m.logsViewer.SelectLineRelative(1)
		return m, nil
	case "ctrl+k":
		// Scroll up relative to selected line
		m.logsViewer.SelectLineRelative(-1)
		return m, nil
	}
	return m, nil
}

// handleHelpKeys handles key presses in help view
func (m Model) handleHelpKeys(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	// Help-specific key handling
	return m, nil
}

// handleCommandBarInput handles input when command bar is active with comprehensive validation
func (m Model) handleCommandBarInput(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	switch {
	case key.Matches(msg, m.keys.Enter):
		command, err := m.commandBar.ExecuteCommand()
		if err != nil {
			// Handle command validation error
			m.errorHandler.Handle(err)
			return m, nil
		}
		return m.processCommand(command)

	case key.Matches(msg, m.keys.Quit):
		m.commandBar.Deactivate()
		return m, nil

	default:
		// Forward input to command bar
		m.commandBar.Update(msg)
		return m, nil
	}
}

// processCommand processes an executed command with enhanced error handling and validation
func (m Model) processCommand(command string) (tea.Model, tea.Cmd) {
	// Validate command first
	if err := m.commandValidator.ValidateCommand(command); err != nil {
		m.errorHandler.Handle(err)
		return m, nil
	}

	// Add command to logs
	m.logsViewer.AddLog("[CMD] Executed: " + command)

	// Process specific commands with error handling
	switch command {
	case ":status":
		return m, m.getMCFStatus()

	case ":logs":
		m.navigation.SetActiveTab(1) // Logs is index 1
		m.currentView = ViewLogs

	case ":help":
		m.navigation.SetActiveTab(2) // Help is index 2
		m.currentView = ViewHelp

	case ":quit":
		m.quitting = true
		m.cancel() // Cancel any ongoing operations
		return m, tea.Quit

	case ":config":
		return m, m.loadMCFConfig()

	case ":refresh":
		return m, m.refreshMCFData()

	case ":export":
		return m, m.exportDashboardData()

	case ":clear":
		// Clear error notifications
		m.errorNotification.DismissAll()
		m.logsViewer.AddLog("[INFO] Error notifications cleared")

	case ":errors":
		// Show error statistics
		return m, m.showErrorStatistics()

	default:
		// Advanced command parsing with argument support
		parts := strings.Split(command, " ")
		switch parts[0] {
		case ":search":
			if len(parts) > 1 {
				return m, m.performMCFSearch(parts[1])
			} else {
				m.errorHandler.Handle(errors.NewValidationError("missing search term", ":search requires a search term"))
			}

		case ":retry":
			// Retry last failed operation
			return m, m.retryLastOperation()

		default:
			m.errorHandler.Handle(errors.NewValidationError("unknown command",
				"Unknown command: "+command+". Type ':help' for available commands"))
		}
	}

	return m, nil
}

